def read_key():
    """Read a single keypress without blocking.  Returns the character or None."""
    if not msvcrt.kbhit():
        return None
    ch = chr(msvcrt.getch())
    # Map common keys
    mapping = {
        "\x08": "BACKSPACE",   # backspace
        "\r": "ENTER",         # enter
        "\n": "ENTER",
        27: "ESCAPE",          # escape
    }
    return mapping.get(ch, ch)


