function sfx(type) {
  if (muted || !audioCtx) return;
  const now = audioCtx.currentTime;
  const osc = audioCtx.createOscillator();
  const gain = audioCtx.createGain();
  const settings = {
    shoot: [720, 980, 0.045, 'square', 0.025],
    hit: [180, 90, 0.12, 'sawtooth', 0.045],
    powerup: [440, 880, 0.18, 'sine', 0.04],
    damage: [140, 55, 0.18, 'triangle', 0.06],
    win: [523, 1046, 0.45, 'sine', 0.05],
    lose: [220, 80, 0.5, 'sawtooth', 0.06]
  }[type] || [300, 300, 0.08, 'sine', 0.03];
  const [start, end, duration, waveType, volume] = settings;
  osc.type = waveType;
  osc.frequency.setValueAtTime(start, now);
  osc.frequency.exponentialRampToValueAtTime(Math.max(1, end), now + duration);
  gain.gain.setValueAtTime(volume, now);
  gain.gain.exponentialRampToValueAtTime(0.001, now + duration);
  osc.connect(gain).connect(audioCtx.destination);
  osc.start(now);
  osc.stop(now + duration);
}

