function shootBullet(x, y) {
  const now = Date.now();
  if (now - lastShot < shootDelay) return;
  lastShot = now;

  const lvl = player.weaponLvl;
  let speed = 8 + lvl * 1.5;
  let size = 4 + lvl;
  let color = '#00e5ff';

  if (lvl >= 3) {
    for (let i = -2; i <= 2; i++) {
      bullets.push({ x: x + i*8, y: y, vx: i * 0.5, vy: -speed, size: size/1.5, color: '#ffeb3b' });
    }
  } else if (lvl >= 2) {
    bullets.push({ x: x - 6, y: y, vx: -1, vy: -speed, size: size/2, color: '#00bcd4' });
    bullets.push({ x: x + 6, y: y, vx: 1, vy: -speed, size: size/2, color: '#00bcd4' });
  } else {
    bullets.push({ x: x, y: y, vx: 0, vy: -speed, size: size, color: color });
  }

  if (lvl >= 2) fireRate = Math.max(80, 200 - lvl * 40);
  sfx('shoot');
}

