    player.y = Math.max(60, Math.min(canvas.height - 40, player.y));
  }

  // Boost/Dash on Shift
  if (keys['ShiftLeft'] || keys['ShiftRight']) {
    const dashSpeed = player.speed * 3;
    if (mouseX === null || mouseY === null) {
      player.x += dx * 1.5;
      player.y += dy * 1.5;
    } else {
      // Dash toward pointer using direct movement, not atan2 steering
      const angle = Math.atan2(mouseY - player.y, mouseX - player.x);
      player.x += Math.cos(angle) * dashSpeed;
      player.y += Math.sin(angle) * dashSpeed;
    }
    player.x = Math.max(20, Math.min(canvas.width - 20, player.x));
    player.y = Math.max(60, Math.min(canvas.height - 40, player.y));

    // Dash particles
    for (let i = 0; i < 5; i++) {
      const angle = Math.random() * Math.PI * 2;
      particles.push({
        x: player.x + (Math.random()-0.5)*10,
        y: player.y + (Math.random()-0.5)*10,
        vx: Math.cos(angle) * 3,
        vy: Math.sin(angle) * 3,
        life: 8, maxLife: 8, size: 2, color: '#

 {
    createParticle(col * TILE_SIZE + TILE_SIZE / 2, row * TILE_SIZE + TILE_SIZE / 2, towerType.color, 1);
  }
}

// ─── Update Wave Timer ─────────────────────────────────────
function updateWaveTimer(dt) {
  waveTimer += dt;

  if (waveTimer > 5 && !waveComplete) {
    // Check if all enemies spawned and killed
    const aliveEnemies = enemies.filter(e => e.alive).length;

    if (aliveEnemies === 0 && totalSpawned >= spawnBudget) {
      waveComplete = true;

      // Show wave banner
      const banner = document.getElementById('wave-banner');
      banner.textContent = `Wave ${wave} Complete!`;
      banner.classList.add('show');

      setTimeout(() => {
        banner.classList.remove('show');

        if (wave >= WAVE_CONFIGS.length) {
          // All waves survived - win!
          gameOver(true);
        } else {
          wave++;
          initWave();

          // Spawn first enemy immediately to prevent instant win
          spawnEnemy();
        }
      }, 2000);
    }

    waveTimer = 0;
  }
}

// ─── Rendering ─────────────────────────────────────────────
function render() {
  ctx.clearRect(0, 0, canvas.width, canvas.height);

  // Draw grid background
  ctx.fillStyle = '#16213e';
  ctx.fillRect(0, 0, GRID_W, GRID_H);

  // Draw path
  ctx.strokeStyle = '#533483';
  ctx.lineWidth = TILE_SIZE / 2;
  ctx.lineCap = 'round';
  ctx.beginPath();
  for (let i = 0; i < path.length; i++) {
    if (i === 0) ctx.moveTo(path[i].x, path[i].y);
    else ctx.lineTo(path[i].x, path[i].y);
  }
  ctx.stroke();

  // Draw waypoints as circles
  for (let wp of path) {
    ctx.fillStyle = '#533483';
    ctx.beginPath();
    ctx.arc(wp.x, wp.y, TILE_SIZE / 2 - 2, 0, Math.PI * 2);
    ctx.fill();
  }

  // Draw towers
  for (let t of towers) {
    if (!t.alive) continue;

    const cx = t.x + TILE_SIZE / 2;
    const cy = t.y + TILE_SIZE / 2;

    // Tower base
    ctx.fillStyle = '#0f3460';
    ctx.fillRect(t.x, t.y, TILE_SIZE, TILE_SIZE);

    // Tower body
    ctx.fillStyle = t.color;
    ctx.beginPath();
    ctx.arc(cx, cy, 15, 0, Math.PI * 2);
    ctx.fill();

    // Range indicator (faint)
    ctx.strokeStyle = 'rgba(78, 204, 163, 0.1)';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.arc(cx, cy, t.range, 0, Math.PI * 2);
    ctx.stroke();

    // Cooldown indicator
    if (t.cooldownTimer > 0) {
      const cooldownAlpha = Math.min(1, t.cooldownTimer / t.cooldown);
      ctx.fillStyle = `rgba(233, 69, 96, ${cooldownAlpha})`;
      ctx.beginPath();
      ctx.arc(cx, cy, 8, 0, Math.PI * 2);
      ctx.fill();
    }

    // Tower label
    ctx.fillStyle = '#fff';
    ctx.font = '10px Arial';
    ctx.textAlign = 'center';
    ctx.fillText(t.name.substring(0, 3), cx, cy + 4);
  }

  // Draw enemies
  for (let e of enemies) {
    if (!e.alive) continue;

    const ex = e.x;
    const ey = e.y;

    // Enemy body
    ctx.fillStyle = e.color;
    ctx.beginPath();
    ctx.arc(ex, ey, e.radius, 0, Math.PI * 2);
    ctx.fill();

    // HP bar
    const hpRatio = e.hp / e.maxHp;
    ctx.fillStyle = '#333';
    ctx.fillRect(ex - 15, ey - 20, 30, 4);
    ctx.fillStyle = hpRatio > 0.5 ? '#4ecca3' : '#e94560';
    ctx.fillRect(ex - 15, ey - 20, 30 * hpRatio, 4);

    // Enemy label
    ctx.fillStyle = '#fff';
    ctx.font = '8px Arial';
    ctx.textAlign = 'center';
    ctx.fillText(Math.floor(e.hp), ex, ey + 4);
  }

  // Draw projectiles
  for (let p of projectiles) {
    if (!p.alive) continue;

    ctx.fillStyle = p.color;
    ctx.beginPath();
    ctx.arc(p.x, p.y, 4, 0, Math.PI * 2);
    ctx.fill();
  }

  // Draw particles
  for (let p of particles) {
    if (!p.alive) continue;

    ctx.globalAlpha = p.life;
    ctx.fillStyle = p.color;
    ctx.beginPath();
    ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
    ctx.fill();
  }
  ctx.globalAlpha = 1.0;

  // Draw hover preview
  if (hoverCol >= 0 && hoverRow >= 0) {
    const hx = hoverCol * TILE_SIZE + TILE_SIZE / 2;
    const hy = hoverRow * TILE_SIZE + TILE_SIZE / 2;

    ctx.strokeStyle = 'rgba(78, 204, 163, 0.5)';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.arc(hx, hy, TOWER_TYPES[selectedTower - 1].range, 0, Math.PI * 2);
    ctx.stroke();

    // Tower preview circle
    ctx.fillStyle = 'rgba(78, 204, 163, 0.2)';
    ctx.beginPath();
    ctx.arc(hx, hy, TOWER_TYPES[selectedTower - 1].range / 2, 0, Math.PI * 2);
    ctx.fill();

    // Cost indicator
    ctx.fillStyle = '#fff';
    ctx.font = '12px Arial';
    ctx.textAlign = 'center';
    ctx.fillText(`$${TOWER_TYPES[selectedTower - 1].cost}`, hx, hy + 4);
  }

  // Draw HUD
  const hud = document.getElementById('hud');
  if (gameState === 'playing') {
    hud.style.display = 'flex';

    document.getElementById('hud-credits').textContent = credits;
    document.getElementById('hud-lives').textContent = lives;
    document.getElementById('hud-wave').textContent = wave;
    document.getElementById('hud-tower').textContent = `${TOWER_TYPES[selectedTower - 1].name} (${selectedTower})`;

    // Update tower select hint
    const hint = document.getElementById('tower-select-hint');
    if (selectedTower === 1) {
      hint.textContent = 'Click empty tile to build &bull; [1] Pulse ($50) &bull; [2] Sniper ($80)';
    } else {
      hint.textContent = 'Click empty tile to build &bull; [1] Pulse ($50) &bull; [2] Sniper ($80)';
    }
  } else {
    hud.style.display = 'none';
  }
}

