function getTile(x, y) {
if (x < 0 || x >= gameState.cols || y < 0 || y >= gameState.rows) return 'wall';
return gameState.grid[y][x];
}

function setTile(x, y, val) {
gameState.grid[y][x] = val;
}

function isWalkable(x, y) {
const t = getTile(x, y);
return t === 'floor' || t === 'goal';
}

function canPush(x, y, dx, dy) {
const nx = x + dx;
const ny = y + dy;
const tx = nx + dx;
const ty = ny + dy;
if (!isWalkable(nx, ny)) return false;
const target = getTile(tx, ty);
return target === 'floor' || target === 'goal';
}

function doPush(x, y, dx, dy) {
const nx = x + dx;
const ny = y + dy;
const tx = nx + dx;
const ty = ny + dy;
setTile(nx, ny, getTile(tx, ty));
setTile(tx, ty, 'floor');
}

function checkWin() {
let allFilled = true;
for (let y = 0; y < gameState.rows; y++) {
for (let x = 0; x < gameState.cols; x++) {
if (gameState.grid[y][x] === 'goal') {
if (getTile(x, y) !== 'crate_on_goal' && getTile(x, y) !== 'crate') {
allFilled = false;
break;
}
}
}
if (!allFilled) break;
}
return allFilled;
}

function handleMove(dx, dy) {
const px = gameState.playerX;
const py = gameState.playerY;
const nx = px + dx;
const ny = py + dy;
if (!isWalkable(nx, ny)) return;
// Check if there's a crate to push
if (getTile(nx, ny) === 'crate' || getTile(nx, ny) === 'crate_on_goal') {
if (!canPush(px, py, dx, dy)) return;
doPush(px, py, dx, dy);
}
// Move player
setTile(px, py, 'floor');
setTile(nx, ny, 'player');
gameState.playerX = nx;
gameState.playerY = ny;
moveCount++;
document.getElementById('moveCounter').textContent = 'Moves: ' + moveCount;

if (checkWin()) {
playSound('win');
showWinScreen();
return;
}

// Push crate animation
const key = 'crate_' + nx + '_' + ny;
crateAnimProgress[key] = 0.3;
animFrame++;
}

function handleUndo() {
if (undoStack.length === 0) return;
const prev = undoStack.pop();
gameState.grid = prev.grid.map(row => row.slice());
gameState.playerX = prev.playerX;
gameState.playerY = prev.playerY;
moveCount = prev.moves;
document.getElementById('moveCounter').textContent = 'Moves: ' + moveCount;

// Restore crate animation progress
crateAnimProgress = {};
animFrame = 0;
}

function showWinScreen() {
const winScreen = document.getElementById('winScreen');
const msgEl = document.getElementById('winMessage');
if (currentLevelIdx === LEVELS.length - 1) {
msgEl.textContent = 'All levels complete!';
document.getElementById('restartBtn').textContent = 'Play Again';
} else {
msgEl.textContent = 'Push all crates to goals!';
document.getElementById('restartBtn').textContent = 'Next Level';
}
winScreen.style.display = 'flex';
}

function hideWinScreen() {
const winScreen = document.getElementById('winScreen');
winScreen.style.display = 'none';
}

function showStartScreen() {
hideWinScreen();
document.getElementById('startScreen').style.display = 'flex';
document.getElementById('levelSelect').style.display = 'none';
isRunning = false;
}

function showLevelSelect() {
hideWinScreen();
document.getElementById('startScreen').style.display = 'none';
document.getElementById('levelSelect').style.display = 'flex';
}

// Rendering
function drawTile(x, y) {
const px = x * TILE;
const py = y * TILE;
const t = getTile(x, y);
if (t === 'wall') {
ctx.fillStyle = '#2d3a4e';
ctx.fillRect(px, py, TILE, TILE);
ctx.strokeStyle = '#1a2538';
ctx.lineWidth = 1;
ctx.strokeRect(px + 0.5, py + 0.5, TILE - 1, TILE - 1);
} else if (t === 'goal') {
ctx.fillStyle = '#4a9eff';
ctx.fillRect(px, py, TILE, TILE);
ctx.strokeStyle = '#2d7ad8';
ctx.lineWidth = 2;
ctx.strokeRect(px + 0.5, py + 0.5, TILE - 1, TILE - 1);
// Draw goal marker X
ctx.fillStyle = 'rgba(255,255,255,0.7)';
ctx.font = 'bold 24px monospace';
ctx.textAlign = 'center';
ctx.textBaseline = 'middle';
ctx.fillText('X', px + TILE/2, py + TILE/2);
} else if (t === 'crate' || t === 'crate_on_goal') {
const cx = x * TILE;
const cy = y * TILE;
// Crate shadow
ctx.fillStyle = 'rgba(0,0,0,0.3)';
ctx.fillRect(cx + 4, cy + 4, TILE - 8, TILE - 8);
// Crate body
ctx.fillStyle = '#e94560';
ctx.fillRect(cx, cy, TILE, TILE);
ctx.strokeStyle = '#c73e54';
ctx.lineWidth = 2;
ctx.strokeRect(cx + 1, cy + 1, TILE - 2, TILE - 2);
// Crate highlight
ctx.fillStyle = 'rgba(255,255,255,0.2)';
ctx.fillRect(cx + 2, cy + 2, TILE/2 - 4, TILE/2 - 4);
if (t === 'crate_on_goal') {
// Crate on goal marker
ctx.fillStyle = '#4a9eff';
ctx.fillRect(cx, cy, TILE, TILE);
ctx.strokeStyle = '#2d7ad8';
ctx.lineWidth = 2;
ctx.strokeRect(cx + 0.5, cy + 0.5, TILE - 1, TILE - 1);
}
// Crate top highlight
ctx.fillStyle = 'rgba(255,255,255,0.3)';
ctx.fillRect(cx + 4, cy + 4, TILE/2 - 8, 6);
} else {
// Floor tile with subtle pattern
ctx.fillStyle = '#1a2744';
ctx.fillRect(px, py, TILE, TILE);
ctx.strokeStyle = 'rgba(255,255,255,0.05)';
ctx.lineWidth = 1;
ctx.strokeRect(px + 0.5, py + 0.5, TILE - 1, TILE - 1);
}

// Draw player
if (t === 'player') {
const pxOff = x * TILE;
const pyOff = y * TILE;
// Player shadow
ctx.fillStyle = 'rgba(0,0,0,0.3)';
ctx.beginPath();
ctx.arc(pxOff + TILE/2, pyOff + TILE/2 + 4, 12, 0, Math.PI * 2);
ctx.fill();
// Player body
ctx.fillStyle = '#0fbc0f';
ctx.beginPath();
ctx.arc(pxOff + TILE/2, pyOff + TILE/2, 14, 0, Math.PI * 2);
ctx.fill();
ctx.strokeStyle = '#0a9e0a';
ctx.lineWidth = 2;
ctx.stroke();
// Player eyes
ctx.fillStyle = 'white';
ctx.beginPath();
ctx.arc(pxOff + TILE/2 - 5, pyOff + TILE/2 - 3, 4, 0, Math.PI * 2);
ctx.fill();
ctx.beginPath();
ctx.arc(pxOff + TILE/2 + 5, pyOff + TILE/2 - 3, 4, 0, Math.PI * 2);
ctx.fill();
ctx.fillStyle = 'black';
ctx.beginPath();
ctx.arc(pxOff + TILE/2 - 5, pyOff + TILE/2 - 3, 2, 0, Math.PI * 2);
ctx.fill();
ctx.beginPath();
ctx.arc(pxOff + TILE/2 + 5, pyOff + TILE/2 - 3, 2, 0, Math.PI * 2);
ctx.fill();
}

// Crate animation (lerp)
if (crateAnimProgress[key] !== undefined && crateAnimProgress[key] < 1) {
const progress = crateAnimProgress[key];
const targetX = x * TILE;
const targetY = y * TILE;
const currentX = px + (targetX - px) * progress;
const currentY = py + (targetY - py) * progress;
ctx.fillStyle = '#e94560';
ctx.fillRect(currentX, currentY, TILE, TILE);
crateAnimProgress[key] += 0.1;
}
}

function render() {
// Clear canvas
ctx.fillStyle = '#0f172a';
ctx.fillRect(0, 0, W, H);

if (!gameState) return;

for (let y = 0; y < gameState.rows; y++) {
for (let x = 0; x < gameState.cols; x++) {
drawTile(x, y);
