// Drawing Functions
function draw() {
    const ctx = cfg.ctx;

    // Clear canvas
    ctx.fillStyle = '#0a0a2e';
    ctx.fillRect(0, 0, cfg.width, cfg.height);

    if (cfg.state !== 'playing' && cfg.state !== 'gameover') return;

    // Draw sky gradient
    const skyGrad = ctx.createLinearGradient(0, 0, 0, cfg.groundY);
    skyGrad.addColorStop(0, '#0a0a2e');
    skyGrad.addColorStop(0.5, '#1a1a4e');
    skyGrad.addColorStop(1, '#2a2a6e');
    ctx.fillStyle = skyGrad;
    ctx.fillRect(0, 0, cfg.width, cfg.groundY);

    // Parallax background layers
    drawParallaxLayer(ctx, 50, 300, 100, '#1a1a4e', 0.2);
    drawParallaxLayer(ctx, 100, 250, 80, '#2a2a6e', 0.3);

    // Draw distant mountains
    ctx.fillStyle = 'rgba(40, 60, 100, 0.3)';
    for (let i = 0; i < 5; i++) {
        const x = ((i * 200 + cfg.distance * 0.5) % cfg.width + cfg.width) % cfg.width - 100;
        ctx.beginPath();
        ctx.moveTo(x, cfg.groundY);
        ctx.lineTo(x + 80, cfg.groundY - 150);
        ctx.lineTo(x + 160, cfg.groundY);
        ctx.fill();
    }

    // Draw ground
    const groundGrad = ctx.createLinearGradient(0, cfg.groundY, 0, cfg.height);
    groundGrad.addColorStop(0, '#2a3a5e');
    groundGrad.addColorStop(1, '#1a2a4e');
    ctx.fillStyle = groundGrad;
    ctx.fillRect(0, cfg.groundY, cfg.width, cfg.height - cfg.groundY);

    // Ground line
    ctx.strokeStyle = 'rgba(79, 195, 247, 0.3)';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(0, cfg.groundY);
    ctx.lineTo(cfg.width, cfg.groundY);
    ctx.stroke();

    // Draw trail behind player
    for (let i = cfg.trail.length - 1; i >= 0; i--) {
        const t = cfg.trail[i];
        ctx.fillStyle = `rgba(79, 195, 247, ${t.alpha * (t.life / 15)})`;
        ctx.fillRect(t.x, t.y - 10, 6, 20);
    }

    // Draw coins
    for (let coin of cfg.coins) {
        if (!coin.collected) {
            const pulse = coin.type === 'powerup' ? Math.sin(coin.pulse) * 3 : 0;

            ctx.fillStyle = coin.type === 'powerup' 
                ? `rgba(255, 215, 0, ${0.8 + Math.sin(coin.pulse) * 0.2})` 
                : '#ffd700';

            const cx = coin.x - pulse;
            const cy = coin.y - pulse;
            ctx.beginPath();
            ctx.arc(cx, cy, coin.width / 2, 0, Math.PI * 2);
            ctx.fill();

            // Draw coin shine
            ctx.fillStyle = 'rgba(255, 255, 255, 0.4)';
            ctx.beginPath();
