    // --- Game Logic Functions (defined before event listeners) ---

    function initGame() {
        const startX = Math.floor(COLS / 2);
        const startY = Math.floor(ROWS / 2);
        snake = [
            { x: startX, y: startY },
            { x: startX - 1, y: startY },
            { x: startX - 2, y: startY }
        ];
        direction = { x: 1, y: 0 };
        nextDirection = { x: 1, y: 0 };
        score = 0;
        updateScoreUI();
    }

    function spawnFood() {
        let validPosition = false;
        while (!validPosition) {
            const fx = Math.floor(Math.random() * COLS);
            const fy = Math.floor(Math.random() * ROWS);
            // Check if position is occupied by snake body
            const onSnake = snake.some(function(segment) { return segment.x === fx && segment.y === fy; });
            if (!onSnake) {
                food = { x: fx, y: fy };
                validPosition = true;
            }
        }
    }

    function updateScoreUI() {
        scoreDisplay.textContent = 'Score: ' + score;
        highScoreDisplay.textContent = 'Best: ' + highScore;
    }

    function gameOver() {
        playSound('die');
        if (score > highScore) {
            highScore = score;
            localStorage.setItem('serpent_grid_high', String(highScore));
        }
        finalScoreText.textContent = 'Final Score: ' + score;
        gameOverScreen.classList.add('visible');
    }

    function gameLoop() {
        if (gameState !== 'playing') return;

        // Update direction from input buffer
        direction = nextDirection;

        const head = { x: snake[0].x + direction.x, y: snake[0].y + direction.y };

        // Wall Collision Check
        if (head.x < 0 || head.x >= COLS || head.y < 0 || head.y >= ROWS) {
            gameOver();
            return;
        }

        // Self Collision Check
        for (let i = 0; i < snake.length; i++) {
            if (snake[i].x === head.x && snake[i].y === head.y) {
                gameOver();
                return;
            }
        }

        snake.unshift(head);

        // Food Collision Check
        if (head.x === food.x && head.y === food.y) {
            score += 10;
            playSound('eat');
            updateScoreUI();
            spawnFood();
            // Don't pop tail, so snake grows
        } else {
            snake.pop();
        }

        draw();
        gameLoopId = requestAnimationFrame(gameLoop);
    }

    function draw() {
        // Clear canvas
        ctx.fillStyle = '#0f3460';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        // Draw Grid (subtle)
        ctx.strokeStyle = 'rgba(255,255,255,0.03)';
        ctx.lineWidth = 1;
        for (let x = 0; x <= COLS; x++) {
            ctx.beginPath();
            ctx.moveTo(x * TILE_SIZE, 0);
            ctx.lineTo(x * TILE_SIZE, canvas.height);
            ctx.stroke();
        }
        for (let y = 0; y <= ROWS; y++) {
            ctx.beginPath();
            ctx.moveTo(0, y * TILE_SIZE);
            ctx.lineTo(canvas.width, y * TILE_SIZE);
            ctx.stroke();
        }

        // Draw Snake
        snake.forEach(function(segment, index) {
            if (index === 0) {
                ctx.fillStyle = '#e94560';
                ctx.shadowColor = '#e94560';
                ctx.shadowBlur = 10;
            } else {
                ctx.fillStyle = '#c73a58';
                ctx.shadowBlur = 0;
            }
            ctx.fillRect(segment.x * TILE_SIZE + 1, segment.y * TILE_SIZE + 1, TILE_SIZE - 2, TILE_SIZE - 2);
        });

        // Draw Food
        if (food) {
            ctx.fillStyle = '#ff4757';
            ctx.shadowColor = '#ff4757';
            ctx.shadowBlur = 8;
            const fx = food.x * TILE_SIZE + TILE_SIZE / 2;
            const fy = food.y * TILE_SIZE + TILE_SIZE / 2;
            ctx.beginPath();
            ctx.arc(fx, fy, TILE_SIZE / 3, 0, Math.PI * 2);
            ctx.fill();
            ctx.shadowBlur = 0;
        }
    }

    // --- Input Handling ---
    function handleInput(key) {
        if (gameState !== 'playing') return;

        switch(key) {
            case 'ArrowUp':
            case 'w':
            case 'W':
                if (direction.y === 0) nextDirection = { x: 0, y: -1 };
                break;
            case 'ArrowDown':
            case 's':
            case 'S':
                if (direction.y === 0) nextDirection = { x: 0, y: 1 };
                break;
            case 'ArrowLeft':
            case 'a':
            case 'A':
                if (direction.x === 0) nextDirection = { x: -1, y: 0 };
                break;
            case 'ArrowRight':
            case 'd':
            case 'D':
                if (direction.x === 0) nextDirection = { x: 1, y: 0 };
                break;
        }
    }

    // --- Event Listeners ---

    function startGame() {
        gameState = 'playing';
        initGame();
        spawnFood();
        draw();

        // Hide overlay immediately
        startOverlay.classList.add('hidden');

        // Focus canvas for keyboard input
        canvas.focus();

        if (gameLoopId) cancelAnimationFrame(gameLoopId);
        gameLoopId = requestAnimationFrame(gameLoop);
    }

    // Start Button
    playBtn.addEventListener('click', startGame);

    // Restart Button
    restartBtn.addEventListener('click', function() {
        gameOverScreen.classList.remove('visible');
        startGame();
    });

    // Keyboard Events (Global for accessibility)
    document.addEventListener('keydown', function(e) {
        if (gameState === 'start' && (e.key === 'Enter' || e.key === ' ') && !e.repeat) {
            e.preventDefault();
            startGame();
        } else if (gameState === 'over' && (e.key === 'Enter' || e.key === ' ') && !e.repeat) {
            e.preventDefault();
            gameOverScreen.classList.remove('visible');
            startGame();
        } else if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight', 'w', 'a', 's', 'd'].indexOf(e.key) !== -1) {
            handleInput(e.key);
        }
    });

    // Canvas Click to Start/Focus
    canvas.addEventListener('click', function() {
        if (gameState === 'start') startGame();
        else if (gameState === 'over') { gameOverScreen.classList.remove('visible'); startGame(); }
        canvas.focus();
    });

})();
