function spawnNote() {
    const lane = Math.floor(Math.random() * 8);
    notes.push({
        lane: lane,
        y: -30,
        hit: false,
        missed: false,
        color: ['#e94560','#f5a623','#7ecf8b','#4da6ff','#c084fc','#fb923c','#6ee7b7','#f472b6'][lane]
    });
}

function update(dt) {
    if (gameState !== 'playing') return;

    spawnTimer += dt;
    if (spawnTimer >= spawnInterval) {
        spawnNote();
        spawnTimer = 0;
    }

    const hitLineY = canvas.height - 100;

    notes.forEach(note => {
        note.y += dt * 300;

        if (!note.hit && !note.missed) {
            // Check miss window (past the hit line)
            if (note.y > hitLineY + hitWindows.good) {
                note.missed = true;
                combo = 1;
                score += 50;
                playSound('miss');
            }
        }
    });

    // Remove notes that have passed far below screen
    notes = notes.filter(n => n.y < canvas.height + 50);
}

function draw() {
    ctx.fillStyle = '#0f0f23';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    if (gameState !== 'playing') return;

    // Draw lanes
    for (let i = 0; i < 8; i++) {
        const x = i * laneWidth;
        ctx.strokeStyle = '#1e2a4a';
        ctx.lineWidth = 1;
        ctx.beginPath();
        ctx.moveTo(x, 0);
        ctx.lineTo(x, canvas.height);
        ctx.stroke();
    }

    // Draw hit line
    const hitLineY = canvas.height - 100;
    ctx.strokeStyle = '#e94560';
    ctx.lineWidth = 3;
    ctx.beginPath();
    ctx.moveTo(0, hitLineY);
    ctx.lineTo(canvas.width, hitLineY);
    ctx.stroke();

    // Draw notes
    notes.forEach(note => {
        if (note.hit) return;

        const x = note.lane * laneWidth + laneWidth / 2;
        const radius = 15;

        ctx.beginPath();
        ctx.arc(x, note.y, radius, 0, Math.PI * 2);
        ctx.fillStyle = note.color;
        ctx.fill();

        // Glow effect
        ctx.shadowColor = note.color;
        ctx.shadowBlur = 15;
        ctx.fill();
        ctx.shadowBlur = 0;
    });

    // Draw combo text
    if (combo > 1) {
        const comboX = canvas.width / 2 - 40;
        const comboY = hitLineY - 60;
        ctx.font = 'bold 36px sans-serif';
        ctx.fillStyle = '#f5a623';
