// === GAME FUNCTIONS ===
function startGame() {
  gameState = 'playing';
  score = 0;
  credits = 50;
  wave = 1;
  enemiesAlive = 0;
  towersPlaced = 0;
  spawnBudget = 0;
  waveEnemiesSpawned = 0;
  lastSpawnTime = Date.now();

  // Reset game objects
  towers.length = 0;
  enemies.length = 0;
  bullets.length = 0;
  particles.length = 0;
  selectedTowerIdx = -1;

  // Hide start overlay, show HUD and wave info
  document.getElementById('start-overlay').classList.add('hidden');
  document.getElementById('hud').style.display = 'flex';
  document.getElementById('wave-info').style.display = 'block';

  playSound('wave');
}

function placeTower(typeIdx) {
  if (gameState !== 'playing') return;

  const type = towerTypes[typeIdx];

  // Find a valid placement position
  for (let r = 0; r < ROWS; r++) {
    for (let c = 0; c < COLS; c++) {
      if (map[r][c] === 3 && map[r][c] !== 2) { // tower spot, not core
        const x = c * TILE;
        const y = r * TILE;

        // Check if already occupied by a tower
        let occupied = false;
        for (let i = 0; i < towers.length; i++) {
          if (towers[i].x === x && towers[i].y === y) {
            occupied = true;
            break;
          }
        }

        if (!occupied && credits >= type.cost) {
          // Place tower
          towers.push({
            x: x, y: y,
            typeIdx: typeIdx,
            cost: type.cost,
            range: type.range,
            damage: type.damage,
            rate: type.rate,
            cooldown: 0,
            target: null
          });

          credits -= type.cost;
          towersPlaced++;
          selectedTowerIdx = -1;
          playSound('powerup');
          return;
        }
      }
    }
  }
}

function placeTowerAt(gx, gy) {
  if (gameState !== 'playing') return;

  const type = towerTypes[selectedTowerIdx];
  if (!type) return;

  // Check bounds and valid placement
  if (gx < 0 || gx >= COLS || gy < 0 || gy >= ROWS) return;

  if (map[gy][gx] !== 3 && map[gy][gx] !== 2) return; // must be tower spot or core

  const x = gx * TILE;
  const y = gy * TILE;

  // Check if already occupied by a tower
  let occupied = false;
  for (let i = 0; i < towers.length; i++) {
    if (towers[i].x === x && towers[i].y === y) {
      occupied = true;
      break;
    }
  }

  if (!occupied && credits >= type.cost) {
    // Place tower
    towers.push({
      x: x, y: y,
      typeIdx: selectedTowerIdx,
      cost: type.cost,
      range: type.range,
      damage: type.damage,
      rate: type.rate,
      cooldown: 0,
      target: null
    });

    credits -= type.cost;
    towersPlaced++;
    selectedTowerIdx = -1;
    playSound('powerup');
  } else if (occupied) {
    // Deselect on click of existing tower
    for (let i = 0; i < towers.length; i++) {
      if (towers[i].x === x && towers[i].y === y) {
        selectedTowerIdx = i;
        break;
      }
    }
  } else {
    // Not enough credits, deselect
    selectedTowerIdx = -1;
  }
}

function showGameOver() {
  gameState = 'gameover';
  document.getElementById('game-over-title').textContent = 'GAME OVER';
  document.getElementById('game-over-score').textContent = 
    `Score: ${score} | Waves Survived: ${wave}`;
  document.getElementById('game-over-overlay').classList.add('visible');

  playSound('lose');
}

function showStartScreen() {
  gameState = 'start';
  document.getElementById('start-overlay').classList.remove('hidden');
  document.getElementById('hud').style.display = 'none';
  document.getElementById('wave-info').style.display = 'none';
  document.getElementById('game-over-overlay').classList.remove('visible');
}

// === INITIALIZATION ===
canvas.addEventListener('click', function() {
  if (gameState === 'start') {
    startGame();
  } else if (gameState === 'gameover') {
    startGame();
  }
});

document.getElementById('play-btn').addEventListener('click', function() {
  startGame();
});

document.getElementById('restart-btn').addEventListener('click', function() {
  startGame();
});

// Start the animation loop immediately (requirement: no static game)
gameLoop();

})();
