  // Draw everything
  function draw() {
    ctx.fillStyle = '#000';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    if (gameState !== 'playing') return;

    // Draw asteroids
    for (var i = 0; i < asteroids.length; i++) {
      var a = asteroids[i];
      ctx.save();
      ctx.translate(a.x, a.y);
      ctx.rotate(a.angle);
      ctx.beginPath();
      ctx.moveTo(a.vertices[0].x, a.vertices[0].y);
      for (var j = 1; j < a.vertices.length; j++) {
        ctx.lineTo(a.vertices[j].x, a.vertices[j].y);
      }
      ctx.closePath();

      var gradient = ctx.createRadialGradient(0, 0, 0, 0, 0, a.radius);
      gradient.addColorStop(0, '#fff');
      gradient.addColorStop(1, '#888');
      ctx.fillStyle = gradient;
      ctx.fill();
      ctx.restore();
    }

    // Draw bullets
    for (var i = 0; i < bullets.length; i++) {
      ctx.beginPath();
      ctx.arc(bullets[i].x, bullets[i].y, 3, 0, Math.PI * 2);
      ctx.fillStyle = '#ff0';
      ctx.fill();
    }

    // Draw particles
    for (var i = 0; i < particles.length; i++) {
      var p = particles[i];
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
      ctx.fillStyle = '#f80';
      ctx.globalAlpha = p.life / 50;
      ctx.fill();
    }

    // Draw powerups
    for (var i = 0; i < powerups.length; i++) {
      var pu = powerups[i];
      ctx.beginPath();
      ctx.arc(pu.x, pu.y, 8, 0, Math.PI * 2);
      ctx.fillStyle = pu.type === 0 ? '#0f0' : pu.type === 1 ? '#ff0' : '#f00';
      ctx.fill();

      // Glow effect
      ctx.beginPath();
      ctx.arc(pu.x, pu.y, 15, 0, Math.PI * 2);
      ctx.fillStyle = 'rgba(255,255,255,0.3)';
      ctx.fill();
    }

    // Draw ship
    ctx.save();
    ctx.translate(ship.x, ship.y);
    ctx.rotate(ship.angle);

    var shipSize = 20;
    ctx.beginPath();
    ctx.moveTo(0, -shipSize);
    ctx.lineTo(-15, shipSize * 0.8);
    ctx.lineTo(0, shipSize * 1.4);
    ctx.lineTo(15, shipSize * 0.8);
    ctx.closePath();

    var shipGradient = ctx.createRadialGradient(0, 0, 0, 0, 0, shipSize);
    shipGradient.addColorStop(0, '#fff');
    shipGradient.addColorStop(1, '#0ff');
    ctx.fillStyle = shipGradient;
    ctx.fill();

    // Thrust flame
    if (ship.thrusting) {
      ctx.beginPath();
      ctx.moveTo(-5, shipSize * 0.8);
      ctx.lineTo(0, shipSize * 1.4 + Math.random() * 15);
      ctx.lineTo(5, shipSize * 0.8);
      ctx.fillStyle = '#f80';
      ctx.fill();
    }

    ctx.restore();
  }

  // Game loop
  function gameLoop() {
    update();
    draw();
    requestAnimationFrame(gameLoop);
  }

