    if (e.key === 'ArrowLeft' || e.key === 'a') keys['ArrowLeft'] = false;
    if (e.key === 'ArrowRight' || e.key === 'd') keys['ArrowRight'] = false;
    if (e.key === 'ArrowUp' || e.key === 'w') keys['ArrowUp'] = false;
