            ctx.strokeStyle = '#fff';
            ctx.lineWidth = 2;
            ctx.stroke();

            // Glow effect
            ctx.beginPath();
            ctx.arc(bumper.x, bumper.y, bumper.r + 5, 0, Math.PI * 2);
            ctx.fillStyle = 'rgba(255, 77, 106, 0.3)';
            ctx.fill();
        }

        // Draw flippers
        for (let flipper of flippers) {
            let flipX = flipper.x + Math.cos(flipper.angle) * flipper.w / 2;
            let flipY = flipper.y + Math.sin(flipper.angle) * flipper.h / 2;

            ctx.beginPath();
            ctx.moveTo(flipper.x, flipper.y);
            ctx.lineTo(flipX, flipY);
            ctx.strokeStyle = '#4ecdc4';
            ctx.lineWidth = 8;
            ctx.lineCap = 'round';
            ctx.stroke();

            // Flipper base
            ctx.beginPath();
            ctx.arc(flipper.x, flipper.y, 15, 0, Math.PI * 2);
            ctx.fillStyle = '#4ecdc4';
            ctx.fill();
        }

        // Draw plunger
        if (plunger.compressed) {
            ctx.beginPath();
            ctx.arc(plunger.x + plunger.w / 2, plunger.y, plunger.h * 0.3, 0, Math.PI * 2);
            ctx.fillStyle = '#e94560';
            ctx.fill();
        } else {
            ctx.beginPath();
            ctx.arc(plunger.x + plunger.w / 2, plunger.y, plunger.h * 0.15, 0, Math.PI * 2);
            ctx.fillStyle = '#e94560';
            ctx.fill();
        }

        // Draw drain lane
        ctx.beginPath();
        ctx.moveTo(300, 750);
        ctx.lineTo(340, 750);
        ctx.strokeStyle = '#ff4d6a';
        ctx.lineWidth = 2;
        ctx.stroke();
    }

    function drawBall() {
        if (!ball) return;

        // Ball glow
        ctx.beginPath();
        ctx.arc(ball.x, ball.y, ball.r + 5, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(78, 205, 196, 0.3)';
        ctx.fill();

        // Ball body
        ctx.beginPath();
        ctx.arc(ball.x, ball.y, ball.r, 0, Math.PI * 2);
        ctx.fillStyle = '#4ecdc4';
        ctx.fill();

        ctx.strokeStyle = '#fff';
        ctx.lineWidth = 2;
        ctx.stroke();

        // Ball shine
        ctx.beginPath();
        ctx.arc(ball.x - 3, ball.y - 3, 5, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(255, 255, 255, 0.6)';
        ctx.fill();
    }

    function drawEnemies() {
        for (let enemy of enemies) {
            if (!enemy.active) continue;

            // Enemy glow
            ctx.beginPath();
            ctx.arc(enemy.x, enemy.y, enemy.r + 3, 0, Math.PI * 2);
            ctx.fillStyle = 'rgba(255, 107, 138, 0.4)';
            ctx.fill();

            // Enemy body
            ctx.beginPath();
            ctx.arc(enemy.x, enemy.y, enemy.r, 0, Math.PI * 2);
            ctx.fillStyle = '#ff6b8a';
            ctx.fill();

            ctx.strokeStyle = '#fff';
            ctx.lineWidth = 1;
            ctx.stroke();

            // Enemy eye
            let angle = Math.atan2(ball ? ball.y - enemy.y : 0, ball ? ball.x - enemy.x : 0);
            ctx.beginPath();
            ctx.arc(enemy.x + Math.cos(angle) * 6, enemy.y + Math.sin(angle) * 6, 4, 0, Math.PI * 2);
            ctx.fillStyle = '#fff';
            ctx.fill();
        }
    }

    function drawPowerups() {
        for (let pu of powerups) {
            if (!pu.active) continue;

            // Powerup glow
            ctx.beginPath();
            ctx.arc(pu.x, pu.y, pu.r + 5, 0, Math.PI * 2);
            ctx.fillStyle = 'rgba(78, 205, 196, 0.3)';
            ctx.fill();

            // Powerup body
            ctx.beginPath();
            ctx.arc(pu.x, pu.y, pu.r, 0, Math.PI * 2);
            ctx.fillStyle = '#4ecdc4';
            ctx.fill();

            ctx.strokeStyle = '#fff';
            ctx.lineWidth = 1;
            ctx.stroke();

            // Powerup icon
            ctx.fillStyle = '#fff';
            ctx.font = '10px Arial';
            ctx.textAlign = 'center';
            ctx.textBaseline = 'middle';
            ctx.fillText(pu.type === 'shield' ? 'S' : 'x2', pu.x, pu.y);
        }
    }

    function drawParticles() {
        for (let p of particles) {
            ctx.beginPath();
            ctx.arc(p.x, p.y, 3 * p.life, 0, Math.PI * 2);
            ctx.fillStyle = p.color;
            ctx.globalAlpha = p.life;
            ctx.fill();
            ctx.globalAlpha = 1.0;
        }
    }

    // Main game loop
    function gameLoop() {
        if (gameState !== 'playing') return;

        frameCount++;

        // Spawn enemies periodically
        if (frameCount % 300 === 0 && enemies.length < 5) {
            let spawnX = Math.random() * (canvas.width - 100) + 50;
            let spawnY = canvas.height - 100;
            enemies.push(createEnemy(spawnX, spawnY));
        }

        // Spawn powerups occasionally
        if (frameCount % 600 === 0 && powerups.length < 2) {
            let puX = Math.random() * (canvas.width - 100) + 50;
            let puY = canvas.height - 150;
            powerups.push(createPowerup(puX, puY));
        }

        updateBall();
        updateEnemies();
        updateParticles();

        drawTable();
        drawBall();
        drawEnemies();
        drawPowerups();
        drawParticles();
        updateUI();

        requestAnimationFrame(gameLoop);
    }

    // Start the game loop when playing state is reached
    if (gameState === 'playing') {
        gameLoop();
    } else {
        // Wait for play to be triggered
        setInterval(function() {
            if (gameState === 'playing') {
                gameLoop();
            }
        }, 16);
    }

})();
