                    ctx.shadowColor = '#f0f';
                    ctx.shadowBlur = 15;
                    ctx.beginPath();
                    ctx.arc(0, 0, enemy.width / 2, 0, Math.PI * 2);
                    ctx.fill();
                } else if (enemy.type === 'fast') {
