                    ctx.fill();
                } else {
                    ctx.fillStyle = '#0ff';
                    ctx.shadowColor = '#0ff';
                    ctx.shadowBlur = 20;
                    ctx.fillRect(-enemy.width / 2, -enemy.height / 2, enemy.width, enemy.height);

                    // HP bar for tanks
                    if (enemy.hp < enemy.maxHp) {
                        const hpWidth = enemy.width * 0.6;
                        ctx.fillStyle = '#333';
                        ctx.fillRect(-hpWidth / 2, -enemy.height / 2 - 8, hpWidth, 4);
                        ctx.fillStyle = '#f00';
                        ctx.shadowColor = '#f00';
