                ctx.beginPath();
                ctx.arc(0, 0, bullet.width / 2, 0, Math.PI * 2);
                ctx.fill();
                ctx.restore();
            }

            // Draw enemy bullets
            for (const bullet of enemyBullets) {
                ctx.save();
                ctx.translate(bullet.x, bullet.y);
                ctx.fillStyle = '#f00';
                ctx.shadowColor = '#f00';
                ctx.shadowBlur = 8;
                ctx.beginPath();
                ctx.arc(0, 0, bullet.width / 2, 0, Math.PI * 2);
                ctx.fill();
                ctx.restore();
            }

            // Draw particles
            for (const particle of particles) {
                ctx.save();
                ctx.globalAlpha = particle.life;
                ctx.fillStyle = particle.color;
                ctx.shadowColor = particle.color;
                ctx.shadowBlur = 5;
                ctx.beginPath();
                ctx.arc(particle.x, particle.y, particle.size * particle.life, 0, Math.PI * 2);
                ctx.fill();
                ctx.restore();
            }

            // Draw player
            if (gameState === 'playing') {
                ctx.save();
                ctx.translate(player.x, player.y);

                // Invincibility flash
                if (player.invincible && Math.floor(Date.now() / 100) % 2 === 0) {
                    ctx.globalAlpha = 0.5;
                }

                ctx.fillStyle = '#fff';
                ctx.shadowColor = '#0ff';
                ctx.shadowBlur = 20;

                // Ship body
                ctx.beginPath();
                ctx.moveTo(0, -player.height / 2);
                ctx.lineTo(player.width / 2, player.height / 2);
                ctx.lineTo(-player.width / 2, player.height / 2);
                ctx.closePath();
                ctx.fill();

                // Engine glow
                const enginePulse = Math.sin(Date.now() / 100) * 5;
                ctx.fillStyle = '#0ff';
                ctx.shadowColor = '#0ff';
                ctx.beginPath();
                ctx.moveTo(-player.width / 4, player.height / 2);
                ctx.lineTo(player.width / 4, player.height / 2);
                ctx.lineTo(0, player.height / 2 + enginePulse);
                ctx.closePath();
                ctx.fill();

                ctx.restore();
            }
        }

        // Initialize Game
        initStars();

        // Start button click handler
        cfg.playBtn.addEventListener('click', () => {
            startGame();
        });

        // Focus canvas on load
        cfg.canvas.focus();

        // Initial render for background
        render();
