}

// ===== DAMAGE =====
function takeDamage() {
    lives--;
    if (lives <= 0) {
        gameState = 'lose';
        playSound('lose');
        showScreen('gameover', `GAME OVER\nScore: ${score}\nItems: ${itemsCollected}`);
        return;
    }

    player.invulnerable = 2000; // 2 second invulnerability
    player.vy = -6;
    player.vx = player.facingRight ? -4 : 4;
    playSound('hit');
}

// ===== LEVEL PROGRESSION =====
function nextLevel() {
    levelIndex++;
    if (levelIndex >= 2) {
        gameState = 'win';
        score += itemsCollected * 100;
        playSound('win');
        showScreen('victory', `VICTORY!\nFinal Score: ${score}\nItems Collected: ${itemsCollected}`);
    } else {
        loadLevel(levelIndex);
    }
}

// ===== SCREEN MANAGEMENT =====
function showScreen(type, text) {
    const overlay = document.getElementById('ui-overlay');
    overlay.innerHTML = `<div style="position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);text-align:center;color:#fff;font-size:24px;line-height:1.8;white-space:pre;">${text}</div>`;
}

// ===== DRAW =====
function draw() {
    const ctx = canvas.getContext('2d');
    const w = canvas.width / (window.devicePixelRatio || 1);
    const h = canvas.height / (window.devicePixelRatio || 1);

    // Clear
    ctx.fillStyle = '#0f0f23';
    ctx.fillRect(0, 0, w, h);

    if (gameState !== 'playing') return;

    ctx.save();
    ctx.translate(-camera.x, 0);

    // Draw platforms
    for (let p of level.platforms) {
        ctx.fillStyle = '#4a9eff';
        ctx.fillRect(p.x, p.y, p.w, p.h);
        ctx.strokeStyle = '#6bb3ff';
        ctx.lineWidth = 2;
        ctx.strokeRect(p.x, p.y, p.w, p.h);
    }

    // Draw hazards (spikes)
    for (let h of level.hazards) {
        ctx.fillStyle = '#ff4444';
        const spikeCount = Math.floor(h.w / 16);
        for (let i = 0; i < spikeCount; i++) {
            ctx.beginPath();
            ctx.moveTo(h.x + i * 16, h.y + h.h);
            ctx.lineTo(h.x + i * 16 + 8, h.y);
            ctx.lineTo(h.x + i * 16 + 16, h.y + h.h);
            ctx.fill();
        }
    }

    // Draw collectibles from level
    for (let c of level.collectibles) {
        if (!c || c.collected) continue;
        drawCollectible(c);
    }

    // Draw dropped items
    for (let d of droppedItems) {
        if (!d || d.collected) continue;
        drawCollectible(d);
    }

    // Draw enemies
    for (let e of level.enemies) {
        if (!e.alive) continue;
        ctx.fillStyle = '#ff6b35';
        ctx.fillRect(e.x, e.y, e.w, e.h);
        // Eyes
        ctx.fillStyle = '#fff';
        const eyeOff = e.dir === 1 ? 14 : 6;
        ctx.fillRect(e.x + eyeOff, e.y + 4, 4, 4);
        ctx.fillRect(e.x + eyeOff + 8, e.y + 4, 4, 4);
    }

    // Draw projectiles
    for (let pr of projectiles) {
        if (!pr.alive) continue;
        ctx.fillStyle = '#ff0';
        ctx.beginPath();
        ctx.arc(pr.x + pr.w/2, pr.y + pr.h/2, 4, 0, Math.PI * 2);
        ctx.fill();
    }

    // Draw player
    if (player.invulnerable > 150) {
        // Flicker when invulnerable
        if ((timestamp / 80) % 2 < 1) return;
    }

    ctx.fillStyle = '#4fc3f7';
    ctx.fillRect(player.x, player.y, player.w, player.h);
    // Eyes to show direction
    ctx.fillStyle = '#fff';
    const eyeOff = player.facingRight ? 12 : 4;
    ctx.fillRect(player.x + eyeOff, player.y + 6, 4, 4);
    ctx.fillRect(player.x + eyeOff + 8, player.y + 6, 4, 4);

    // Shield effect
    if (player.shield > 0) {
        ctx.strokeStyle = '#0ff';
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.arc(player.x + player.w/2, player.y + player.h/2, 28, 0, Math.PI * 2);
        ctx.stroke();
    }

    // Speed boost effect
    if (player.speedBoost > 0) {
        ctx.strokeStyle = '#ff0';
        ctx.lineWidth = 1;
        for (let i = -3; i <= 3; i++) {
            const angle = Math.PI / 4 + i * 0.5;
            const len = 20 + Math.sin(timestamp / 200 + i) * 5;
            ctx.beginPath();
            ctx.moveTo(player.x + player.w/2, player.y + player.h);
            ctx.lineTo(player.x + player.w/2 + Math.cos(angle) * len, player.y + player.h + Math.sin(angle) * len);
            ctx.stroke();
        }
    }

    // Clone shot effect
    if (player.cloneShot > 0) {
        const cloneX = player.x + player.facingRight ? player.w : -24;
        const cloneY = player.y;
        ctx.fillStyle = '#ff6';
        ctx.fillRect(cloneX, cloneY, 18, 28);
    }

    // Draw exit/door at end of level
    ctx.fillStyle = '#ff9800';
    ctx.fillRect(level.exitX - camera.x, level.exitY - camera.y, 40, 32);
    ctx.strokeStyle = '#e65100';
    ctx.lineWidth = 2;
    ctx.strokeRect(level.exitX - camera.x, level.exitY - camera.y, 40, 32);

    ctx.restore();

    // ===== HUD =====
    drawHUD(w, h);
}

function drawCollectible(item) {
    const cx = item.x - camera.x;
    const cy = item.y - camera.y;
    if (cx < -10 || cx > w + 10 || cy < -10 || cy > h + 10) return;

    ctx.fillStyle = '#ffd700';
    ctx.beginPath();
    ctx.arc(cx + 8, cy + 8, 6, 0, Math.PI * 2);
    ctx.fill();
    ctx.strokeStyle = '#daa520';
    ctx.lineWidth = 1;
    ctx.stroke();

    // Gem sparkle
    if (item.type === 'gem') {
        ctx.fillStyle = '#00e5ff';
        ctx.beginPath();
        ctx.arc(cx + 6, cy + 6, 3, 0, Math.PI * 2);
        ctx.fill();
    }

    // Powerup glow
    if (item.type === 'powerup') {
        const pulse = Math.sin(timestamp / 200) * 3;
        ctx.strokeStyle = `rgba(255,100,0,${0.6 + pulse/30})`;
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.arc(cx + 8, cy + 8, 14 + pulse, 0, Math.PI * 2);
        ctx.stroke();
    }

    // Dropped item timer indicator (fading)
    if (item.spawnTime && timestamp - item.spawnTime > 5000) {
        const alpha = 1 - (timestamp - item.spawnTime) / 10000;
        ctx.fillStyle = `rgba(255,255,255,${alpha})`;
        ctx.beginPath();
        ctx.arc(cx + 8, cy + 8, 6, 0, Math.PI * 2);
        ctx.fill();
    }
}

function drawHUD(w, h) {
    const ctx = canvas.getContext('2d');
    // Score
    ctx.fillStyle = '#fff';
    ctx.font = '14px Courier New';
    ctx.fillText(`SCORE: ${score}`, 10, 20);
    // Lives
    ctx.fillStyle = '#ff6b35';
    for (let i = 0; i < lives; i++) {
        ctx.fillRect(w - 80 + i * 14, 14, 10, 10);
    }
    // Items collected
    ctx.fillStyle = '#ffd700';
    ctx.fillText(`ITEMS: ${itemsCollected}/${totalItems}`, w - 200, 20);
}

// ===== LOAD LEVEL =====
function loadLevel(index) {
    const lvl = createLevel(index);
    level = lvl;
    player.x = lvl.spawnPoint.x;
    player.y = lvl.spawnPoint.y;
    player.vx = 0;
    player.vy = 0;
    player.grounded = true;
    player.coyoteTimer = COYOTE_TIME;
    player.jumpBuffered = false;
    player.invulnerable = 1500; // brief invulnerability on level start
    projectiles = [];
    droppedItems = [];
}

// ===== GAME LOOP =====
function gameLoop(timestamp) {
    update(timestamp);
    draw();
    requestAnimationFrame(gameLoop);
}

// ===== START SCREEN =====
showScreen('menu', 'CAPTAIN COMIC\nPress PLAY to start');

// ===== INITIALIZATION =====
loadLevel(0);
lastTime = performance.now();
requestAnimationFrame(gameLoop);

})();
</script>
