function drawPlayer(ctx, p, camX) {
    var px = p.x - camX;
    var py = p.y - camX;

    if (p.invincibleTimer > 0 && Math.floor(Date.now() / 80) % 2 === 0) return;

    // Body
    ctx.fillStyle = '#3366cc';
    ctx.fillRect(px, py, PLAYER_W, PLAYER_H);

    // Head
    ctx.fillStyle = '#ffcc99';
    ctx.fillRect(px + 4, py - 8, 16, 12);

    // Eyes
    ctx.fillStyle = '#fff';
    if (p.vx >= 0.5) {
        ctx.fillRect(px + 10, py - 5, 4, 4);
        ctx.fillRect(px + 16, py - 5, 4, 4);
    } else if (p.vx <= -0.5) {
        ctx.fillRect(px + 4, py - 5, 4, 4);
        ctx.fillRect(px + 10, py - 5, 4, 4);
    }

    // Mouth
    ctx.fillStyle = '#cc6633';
    if (p.vx >= 0.5) {
        ctx.fillRect(px + 12, py + 2, 4, 2);
    } else {
        ctx.fillRect(px + 6, py + 2, 4, 2);
    }

    // Legs
    ctx.fillStyle = '#334477';
    if (Math.abs(p.vy) > 1 || Math.abs(p.vx) > 0.5) {
        // Running animation
        var legOffset = Math.sin(Date.now() / 50) * 6;
        ctx.fillRect(px + 2, py + PLAYER_H - 4, 8, 4);
        ctx.fillRect(px + PLAYER_W - 10, py + PLAYER_H - 4, 8, 4);
    } else {
        // Standing
        ctx.fillRect(px + 6, py + PLAYER_H - 2, 6, 2);
        ctx.fillRect(px + PLAYER_W - 12, py + PLAYER_H - 2, 6, 2);
    }

    // Speed boost indicator
    if (p.speedBoostTimer > 0) {
        ctx.strokeStyle = '#ffff44';
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.arc(px + PLAYER_W/2, py - 8, 16, 0, Math.PI * 2);
        ctx.stroke();
    }

    // Jump boost indicator
    if (JUMP_FORCE < -14) {
        ctx.strokeStyle = '#ffaa00';
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.arc(px + PLAYER_W/2, py + PLAYER_H/2, 18, 0, Math.PI * 2);
        ctx.stroke();
    }
}

