// ===== DAMAGE / DEATH =====
function takeDamage() {
    if (player.invincibleTimer > 0 || player.shieldTimer > 0) return;

    lives--;
    playSound('hit');
    createParticles(player.x + PLAYER_W/2, player.y + PLAYER_H/2, '#ff0000', 15);

    if (lives <= 0) {
        gameState = 'lost';
        document.getElementById('loseScore').textContent = 'Final Score: ' + score;
        document.getElementById('loseScreen').style.display = 'flex';
    } else {
        player.invincibleTimer = 1500;
        player.vy = -6;
        player.vx = 0;
    }
}

// ===== COLLISION HELPERS =====
function rectOverlap(x1, y1, w1, h1, x2, y2, w2, h2) {
    return x1 < x2 + w2 && x1 + w1 > x2 && y1 < y2 + h2 && y1 + h1 > y2;
}

// ===== GAME LOOP =====
function gameLoop(timestamp) {
    update();
    draw();

    if (gameState === 'playing' || gameState === 'won') {
        requestAnimationFrame(gameLoop);
    }
}

