        ctx.fillRect(px + eyeOffset + 10, py + 2, 5, 5);

        // Pupils
        ctx.fillStyle = '#000';
        const pupilOffset = player.facingRight ? 4 : -4;
        ctx.fillRect(px + eyeOffset + pupilOffset, py + 3, 3, 3);
        ctx.fillRect(px + eyeOffset + 10 + pupilOffset, py + 3, 3, 3);

        // Mouth (smile when grounded)
        if (player.grounded) {
            ctx.fillStyle = '#2d6a4f';
            ctx.fillRect(px + 8, py + 15, 12, 3);
        }

        // Shield effect
        if (player.shield > 0) {
            ctx.strokeStyle = '#e94560';
            ctx.lineWidth = 2;
            ctx.beginPath();
            ctx.arc(px + player.w/2, py + player.h/2, 22, 0, Math.PI * 2);
            ctx.stroke();
        }

        // Speed boost effect (trails)
        if (player.speedBoost > 0) {
            ctx.fillStyle = 'rgba(233,69,96,0.5)';
            ctx.fillRect(px - 10, py + 4, 8, player.h);
            ctx.fillRect(px + player.w - 6, py + 4, 8, player.h);
        }
    }

    // Draw particles
    for (let p of particles) {
        const px = p.x - cameraX + 100, py = p.y;
        ctx.globalAlpha = Math.min(1, p.life / 30);
        ctx.fillStyle = p.color;
        ctx.fillRect(px, py, 4, 4);
    }
    ctx.globalAlpha = 1;

    // Draw goal/exit
    const goal = level.goal;
    const gx = goal.x - cameraX + 100, gy = goal.y;

    // Goal pole
    ctx.fillStyle = '#fca311';
    ctx.fillRect(gx + 12, gy - 40, 6, 50);

    // Flag
    ctx.fillStyle = '#e94560';
    ctx.beginPath();
    ctx.moveTo(gx + 18, gy - 35);
    ctx.lineTo(gx + 45, gy - 25);
    ctx.lineTo(gx + 18, gy - 15);
    ctx.closePath();
    ctx.fill();

    // Goal glow
    ctx.shadowColor = '#fca311';
    ctx.shadowBlur = 20;
    ctx.fillStyle = 'rgba(252,163,17,0.3)';
