    // HUD overlay (always visible when playing)
    if (gameState === 'playing') {
        ctx.fillStyle = 'rgba(0,0,0,0.5)';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        ctx.font = '16px Courier New';
        ctx.textAlign = 'left';
        ctx.fillStyle = '#fca311';
        ctx.fillText(`SCORE: ${score}`, 20, 45);

        ctx.textAlign = 'center';
        ctx.fillStyle = '#a8dadc';
        ctx.fillText(`LEVEL ${currentLevel}/${MAX_LEVELS}`, canvas.width/2, 45);

        ctx.textAlign = 'right';
        let hearts = '';
        for(let i=0;i<lives;i++) hearts += '♥';
        ctx.fillStyle = '#e94560';
        ctx.fillText(`HP: ${hearts}`, canvas.width - 20, 45);
    }

    // Pause indicator
    if (gameState === 'paused') {
        ctx.fillStyle = 'rgba(0,0,0,0.7)';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        ctx.fillStyle = '#fca311';
        ctx.font = 'bold 48px Courier New';
        ctx.textAlign = 'center';
        ctx.fillText('PAUSED', canvas.width/2, canvas.height/2 - 20);

        ctx.fillStyle = '#a8dadc';
        ctx.font = '16px Courier New';
        ctx.fillText('Press ESC to resume', canvas.width/2, canvas.height/2 + 30);
    }

    // Game over screen
    if (gameState === 'lose') {
        ctx.fillStyle = 'rgba(0,0,0,0.8)';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        ctx.fillStyle = '#ff4757';
        ctx.font = 'bold 48px Courier New';
        ctx.textAlign = 'center';
        ctx.fillText('GAME OVER', canvas.width/2, canvas.height/2 - 30);

        ctx.fillStyle = '#fca311';
        ctx.font = '24px Courier New';
        ctx.fillText(`Score: ${score}`, canvas.width/2, canvas.height/2 + 20);
    }

    // Win screen
    if (gameState === 'win') {
        ctx.fillStyle = 'rgba(0,0,0,0.8)';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        ctx.fillStyle = '#fca311';
        ctx.font = 'bold 48px Courier New';
        ctx.textAlign = 'center';
        ctx.fillText('YOU WIN!', canvas.width/2, canvas.height/2 - 50);

        ctx.fillStyle = '#a8dadc';
        ctx.font = '24px Courier New';
        ctx.fillText(`Final Score: ${score}`, canvas.width/2, canvas.height/2 + 10);
    }

    // Update last time for frame rate calculation
    lastTime = Date.now();
}

// === GAME LOOP ===
function gameLoop(timestamp) {
    const dt = timestamp - lastTime;
    lastTime = timestamp;

    update(dt);
    draw();

    requestAnimationFrame(gameLoop);
}

// === INITIALIZATION ===
updateHUD();

// Start the game loop immediately (renders menu background)
requestAnimationFrame(gameLoop);

})();
