// === DIE FUNCTION ===
function die() {
  playSound('die');
  lives--;
  updateHUD();

  // Spawn death particles
  for (let p = 0; p < 20; p++) {
    particles.push({
      x: player.x + player.w/2, y: player.y + player.h/2,
      vx: (Math.random() - 0.5) * 8,
      vy: (Math.random() - 0.5) * 8,
      life: 40,
      color: '#e94560',
      size: Math.random() * 5 + 3
    });
  }

  if (lives <= 0) {
    gameState = 'lost';
    setTimeout(() => showGameOver(), 800);
  } else {
    player.x = 80;
    player.y = 350;
    player.vx = 0;
    player.vy = 0;
    player.invincible = 90; // 1.5 seconds
    updateHUD();
  }
}

// === NEXT LEVEL / WIN ===
function nextLevel() {
  playSound('win');
  if (currentLevel < totalLevels - 1) {
    currentLevel++;
    loadLevel(currentLevel);
    updateHUD();
  } else {
    gameState = 'won';
    setTimeout(() => showWin(), 800);
  }
}

// === DRAW FUNCTION ===
function draw() {
  // Always fill dark background first
  ctx.fillStyle = '#1a1a3e';
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  if (gameState !== 'playing' && gameState !== 'won') return;

  const camX = cameraX;

  // Draw platforms
  for (let p of levelPlatforms) {
    const px = p.x - camX;
    if (px + p.w < 0 || px > canvas.width) continue;

    ctx.fillStyle = '#4ecca3';
    ctx.fillRect(px, p.y, p.w, p.h);

    // Platform highlight
    ctx.fillStyle = 'rgba(255,255,255,0.15)';
    ctx.fillRect(px, p.y, p.w, 4);
  }

  // Draw hazards (spikes)
  for (let h of hazards) {
    const hx = h.x - camX;
    if (hx + h.w < 0 || hx > canvas.width) continue;

    ctx.fillStyle = '#e94560';
    ctx.beginPath();
    ctx.moveTo(hx, h.y + h.h);
    ctx.lineTo(hx + h.w/2, h.y);
    ctx.lineTo(hx + h.w, h.y + h.h);
    ctx.closePath();
    ctx.fill();
  }

  // Draw coins/drops
  for (let d of drops) {
    const dx = d.x - camX;
    if (dx + d.w < 0 || dx > canvas.width) continue;

    const bobY = Math.sin(Date.now() / 200 + d.bobOffset) * 3;

    ctx.fillStyle = '#f5a623';
    ctx.beginPath();
    ctx.arc(dx + d.w/2, d.y + d.h/2 + bobY, 8, 0, Math.PI * 2);
    ctx.fill();

    // Coin shine
    ctx.fillStyle = 'rgba(255,255,255,0.4)';
    ctx.beginPath();
    ctx.arc(dx + d.w/2 - 3, d.y + d.h/2 + bobY - 3, 3, 0, Math.PI * 2);
    ctx.fill();
  }

  // Draw live enemies
  for (let e of liveEnemies) {
    const ex = e.x - camX;
    if (ex + e.w < 0 || ex > canvas.width) continue;

    ctx.fillStyle = '#e94560';
    ctx.fillRect(ex, e.y, e.w, e.h);

    // Enemy eyes
    ctx.fillStyle = '#fff';
    const eyeOffset = e.dir === 1 ? 4 : -4;
    ctx.fillRect(ex + e.w/2 + eyeOffset - 3, e.y + 6, 5, 5);
    ctx.fillRect(ex + e.w/2 + eyeOffset + 3, e.y + 6, 5, 5);

    // Enemy glow
    ctx.fillStyle = 'rgba(233,69,96,0.3)';
    ctx.fillRect(ex - 4, e.y - 4, e.w + 8, e.h + 8);
  }

  // Draw player (with invincibility flicker)
  if (player.invincible <= 0 || Math.floor(player.invincible / 4) % 2 === 0) {
    const px = player.x - camX;

    ctx.fillStyle = '#4ecca3';
    ctx.fillRect(px, player.y, player.w, player.h);

    // Player eyes (directional)
    ctx.fillStyle = '#1a1a3e';
    const eyeOffset = player.facingRight ? 6 : -2;
    ctx.fillRect(px + player.w/2 + eyeOffset - 2, player.y + 8, 4, 4);
    ctx.fillRect(px + player.w/2 + eyeOffset + 2, player.y + 8, 4, 4);

    // Player glow when jumping
    if (player.vy < -5) {
      ctx.fillStyle = 'rgba(78,204,163,0.3)';
      ctx.fillRect(px - 4, player.y - 4, player.w + 8, player.h + 8);
    }

    // Invincibility flash
    if (player.invincible > 0 && Math.floor(player.invincible / 5) % 2 === 1) {
      ctx.fillStyle = 'rgba(78,204,163,0.5)';
      ctx.fillRect(px - 2, player.y - 2, player.w + 4, player.h + 4);
    }
  }

  // Draw particles
  for (let p of particles) {
    const px = p.x - camX;
    if (px < -10 || px > canvas.width + 10) continue;

    ctx.fillStyle = p.color;
    ctx.globalAlpha = p.life / 30;
    ctx.fillRect(px, p.y, p.size, p.size);
  }
  ctx.globalAlpha = 1;
}

// === GAME LOOP (ALWAYS schedules RAF unconditionally) ===
function gameLoop() {
  update();
  draw();
  requestAnimationFrame(gameLoop); // NEVER gated on gameState - this keeps the chain alive
}

// === OVERLAY SCREENS ===
function showGameOver() {
  overlay.innerHTML = '<h1 style="color:#e94560">GAME OVER</h1><p>Score: ' + score + '</p><button class="btn" id="restartLevelBtn">TRY AGAIN</button>';
}

function showWin() {
  overlay.innerHTML = '<h1 style="color:#f5a623">YOU WIN!</h1><p>Final Score: ' + score + '</p><button class="btn" id="playAgainBtn">PLAY AGAIN</button>';
}

// === START GAME (KICKS THE LOOP) ===
function startGame() {
  gameState = 'playing';
  currentLevel = 0;
  lives = 3;
  score = 0;

  loadLevel(currentLevel);
  updateHUD();

  // KICK THE LOOP - this is critical to prevent grey screen
  requestAnimationFrame(gameLoop);
}

// === BUTTON WIRING (addEventListener only, unique IDs) ===
const playBtn = document.getElementById('playBtn');
playBtn.addEventListener('click', () => {
  overlay.classList.add('hidden');
  canvas.focus();
  startGame();
});

const restartLevelBtn = document.getElementById('restartLevelBtn');
if (restartLevelBtn) {
  restartLevelBtn.addEventListener('click', () => {
    loadLevel(currentLevel);
    updateHUD();
    requestAnimationFrame(gameLoop); // Ensure loop is running
  });
}

const playAgainBtn = document.getElementById('playAgainBtn');
if (playAgainBtn) {
  playAgainBtn.addEventListener('click', () => {
    overlay.classList.add('hidden');
    startGame();
  });
}

// === INITIALIZE ===
updateHUD(); // Show initial HUD even in menu
})();
