        // Platform edge
        ctx.strokeStyle = '#6bb3ff';
        ctx.lineWidth = 1;
        ctx.strokeRect(px, plat.y, plat.w, plat.h);
    }
}

function drawPlayer(ctx) {
    if (gameState !== 'playing') return;
    const px = player.x - cameraX;
    ctx.fillStyle = player.invincible ? '#ffffff' : player.color;
    ctx.fillRect(px, player.y, player.width, player.height);

    // Eyes / face direction
    ctx.fillStyle = '#1a1a2e';
    if (player.vx > 0) {
        ctx.fillRect(px + player.width - 8, player.y + 6, 4, 4);
    } else if (player.vx < 0) {
        ctx.fillRect(px + 4, player.y + 6, 4, 4);
    }

    // Duck indicator
    if (player.ducking) {
        ctx.fillStyle = '#ffaa00';
        ctx.fillRect(px + 8, player.y + 12, 20, 3);
    }
}

function drawEnemies(ctx) {
    for (const e of enemies) {
        const ex = e.x - cameraX;
        if (ex < -40 || ex > canvas.width + 40) continue;

        ctx.fillStyle = e.color;
        ctx.fillRect(ex, e.y, e.width, e.height);

        // HP bar for guards
        if (e.type === 'guard' && e.hp < e.maxHp) {
            ctx.fillStyle = '#333';
            ctx.fillRect(ex + 2, e.y - 8, e.width - 4, 4);
            ctx.fillStyle = '#ff0000';
            ctx.fillRect(ex + 2, e.y - 8, (e.width - 4) * (e.hp / e.maxHp), 4);
        }

        // Eyes
        ctx.fillStyle = '#fff';
        if (Math.abs(e.x - player.x) < 100) {
            const lookDir = player.x > e.x ? 1 : -1;
            ctx.fillRect(ex + 6, e.y + 4, 3, 3);
            ctx.fillRect(ex + e.width - 9, e.y + 4, 3, 3);
        } else {
            ctx.fillRect(ex + 6, e.y + 4, 3, 3);
            ctx.fillRect(ex + e.width - 9, e.y + 4, 3, 3);
        }
    }
}

function drawCoins(ctx) {
    for (const c of coins) {
        const cx = c.x - cameraX;
        if (cx < -20 || cx > canvas.width + 20) continue;

        ctx.fillStyle = '#ffd700';
        ctx.beginPath();
        ctx.arc(cx + c.width / 2, c.y + c.height / 2, c.width / 2, 0, Math.PI * 2);
        ctx.fill();
        ctx.strokeStyle = '#ffaa00';
        ctx.lineWidth = 1;
        ctx.stroke();

        // Sparkle
        if (Math.floor(Date.now() / 200) % 2 === 0) {
            ctx.fillStyle = 'rgba(255, 255, 255, 0.7)';
            ctx.beginPath();
            ctx.arc(cx + c.width / 2 - 3, c.y + c.height / 2 - 4, 2, 0, Math.PI * 2);
            ctx.fill();
        }
    }
}

function drawPowerups(ctx) {
    for (const p of powerups) {
        const px = p.x - cameraX;
        if (px < -20 || px > canvas.width + 20) continue;

        ctx.fillStyle = '#44ff44';
        ctx.beginPath();
        ctx.arc(px + p.width / 2, p.y + p.height / 2, p.width / 2, 0, Math.PI * 2);
        ctx.fill();

        // Shield icon
        ctx.strokeStyle = '#fff';
        ctx.lineWidth = 1.5;
        ctx.beginPath();
        ctx.arc(px + p.width / 2, p.y + p.height / 2, p.width / 3, 0, Math.PI * 2);
        ctx.stroke();

        // Glow effect
        ctx.fillStyle = 'rgba(68, 255, 68, 0.1)';
        ctx.beginPath();
        ctx.arc(px + p.width / 2, p.y + p.height / 2, p.width / 2 + 4, 0, Math.PI * 2);
        ctx.fill();
    }
}

function drawObstacles(ctx) {
    for (const o of obstacles) {
        const ox = o.x - cameraX;
        if (ox < -60 || ox > canvas.width + 60) continue;

        ctx.fillStyle = '#555';
        ctx.fillRect(ox, o.y, o.width, o.height);
        ctx.strokeStyle = '#777';
        ctx.lineWidth = 1;
        ctx.strokeRect(ox, o.y, o.width, o.height);
    }
}

function drawParticles(ctx) {
    for (const p of particles) {
        const alpha = p.life * p.life;
        ctx.fillStyle = p.color + Math.floor(alpha * 255).toString(16).padStart(2, '0');
        ctx.globalAlpha = alpha;
        ctx.fillRect(p.x - cameraX, p.y, p.size, p.size);
    }
    ctx.globalAlpha = 1.0;
}

// --- Main Game Loop ---
function gameLoop(timestamp) {
    requestAnimationFrame(gameLoop); // Always continue the RAF chain

    const dt = Math.min((timestamp - lastTime) / 16.67, 2); // clamp delta time
    lastTime = timestamp;

    if (gameState === 'playing') {
        updatePlayer(dt);
        updateEnemies(dt);
        updateCoins(dt);
        updatePowerups(dt);
        updateParticles(dt);
        updateWave(dt);

        // Camera follows player with smooth scroll
        cameraX = Math.max(0, player.x - 100);

        // Score from distance
        score += dt * 0.5;

        // Wave progression based on distance
        wave = 1 + Math.floor(distance / 500);

        // Keep the HUD live (score/lives/wave updated every frame)
        updateHUD();

        // Check for win condition
        checkWin();
    } else if (gameState === 'start') {
        cameraX = 0;
    }

    // --- Render ---
    const ctx = canvas.getContext('2d');
    drawBackground(ctx, cameraX);
    drawPlatforms(ctx);
    drawObstacles(ctx);
    drawCoins(ctx);
    drawPowerups(ctx);
    drawEnemies(ctx);
    drawPlayer(ctx);
    drawParticles(ctx);

    if (gameState === 'playing') {
        ctx.fillStyle = '#ffd700';
        ctx.font = '12px Courier New';
        ctx.textAlign = 'center';
        ctx.fillText('Wave: ' + wave, canvas.width / 2, 35);
    }

    if (gameState === 'start') {
        ctx.fillStyle = '#1a1a3e';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.strokeStyle = 'rgba(255, 215, 0, 0.1)';
        ctx.lineWidth = 2;
        for (let i = -1; i <= 6; i++) {
            const x = i * 133 + canvas.width / 2;
            ctx.beginPath();
            ctx.moveTo(x, groundY);
            ctx.lineTo(x, groundY + 40);
            ctx.stroke();
        }
    }

    lastTime = timestamp;
}

// --- Update HUD (separate score and lives display) ---
