        ctx.fillStyle = '#1a1a2e';
        ctx.fillRect(px + 3, py + 8, 4, 4);
        ctx.fillRect(px + 3, py + 16, 4, 4);
    } else {
        // Facing right default
        ctx.fillStyle = '#1a1a2e';
        ctx.fillRect(px + player.width - 7, py + 8, 4, 4);
        ctx.fillRect(px + player.width - 7, py + 16, 4, 4);
