function drawEnemies(ctx) {
    for (const e of enemies) {
        const ex = e.x - cameraX;
        if (ex < -50 || ex > canvas.width + 50) continue;

        // Body
        ctx.fillStyle = e.color;
        ctx.fillRect(ex, e.y, e.w, e.h);

        // HP bar for guards/bosses
        if ((e.type === 'guard' || e.type === 'boss') && e.hp < e.maxHp) {
            const barX = ex - 2;
            const barY = e.y - 10;
            ctx.fillStyle = '#333';
            ctx.fillRect(barX, barY, e.w + 4, 5);
            const hpRatio = e.hp / e.maxHp;
            if (hpRatio > 0.6) ctx.fillStyle = '#44ff44';
            else if (hpRatio > 0.3) ctx.fillStyle = '#ffff44';
            else ctx.fillStyle = '#ff0000';
            ctx.fillRect(barX, barY, (e.w + 4) * hpRatio, 5);
        }

        // Eyes - look at player
        const eyeDir = Math.abs(e.x - player.x) < 200 ? (player.x > e.x ? 1 : -1) : 1;
        ctx.fillStyle = '#fff';
        if (eyeDir === 1) {
            ctx.fillRect(ex + e.w - 8, e.y + 4, 3, 3);
        } else {
            ctx.fillRect(ex + 2, e.y + 4, 3, 3);
        }

