    // Parallax Layer 2: vault pillars (medium scroll)
    const pillarSpeed = 0.5;
    for (let px = -camX * pillarSpeed % 120; px < canvas.width + 60; px += 120) {
        ctx.fillStyle = '#2a2a5e';
