  function update() {
    // Paddle movement (keyboard)
    paddle.x += paddle.dx;
    if (paddle.x < 0) paddle.x = 0;
    if (paddle.x + paddle.w > W) paddle.x = W - paddle.w;

    // Ball movement
    ball.x += ball.dx;
    ball.y += ball.dy;

    // Wall collisions
    if (ball.x - ball.r <= 0 || ball.x + ball.r >= W) {
      ball.dx *= -1;
      ball.x = Math.max(ball.r, Math.min(W - ball.r, ball.x));
    }
    if (ball.y - ball.r <= 0) {
      ball.dy *= -1;
      ball.y = ball.r;
    }

    // Paddle collision
    if (
      ball.dy > 0 &&
      ball.y + ball.r >= paddle.y &&
      ball.y + ball.r <= paddle.y + paddle.h + 5 &&
      ball.x >= paddle.x - ball.r &&
      ball.x <= paddle.x + paddle.w + ball.r
    ) {
      // Calculate hit position relative to center of paddle (0 = left, 1 = right)
      const hitPos = (ball.x - paddle.x) / paddle.w;
      // Angle based on where it hits the paddle
      const angle = (-Math.PI / 2) + hitPos * Math.PI * 0.8;
      ball.dx = Math.cos(angle) * ball.speed;
      ball.dy = Math.sin(angle) * ball.speed;
      ball.y = paddle.y - ball.r - 1;

      // Speed up slightly on each paddle hit
      const maxSpeed = 9;
      if (Math.abs(ball.dx) < maxSpeed || Math.abs(ball.dy) < maxSpeed) {
        ball.speed = Math.min(Math.sqrt(ball.dx * ball.dx + ball.dy * ball.dy), maxSpeed);
      }

      spawnParticles(ball.x, ball.y, '#ffffff', 8);
    }

    // Brick collisions
    let allBricksCleared = true;
    for (let r = 0; r < brickRows; r++) {
      for (let c = 0; c < brickCols; c++) {
        const b = bricks[r][c];
        if (!b.alive) continue;

        allBricksCleared = false;

        if (
          ball.x + ball.r > b.x &&
          ball.x - ball.r < b.x + b.w &&
          ball.y + ball.r > b.y &&
          ball.y - ball.r < b.y + b.h
        ) {
          // Determine collision side
          const overlapLeft = (ball.x + ball.r) - b.x;
          const overlapRight = (b.x + b.w) - (ball.x - ball.r);
          const overlapTop = (ball.y + ball.r) - b.y;
          const overlapBottom = (b.y + b.h) - (ball.y - ball.r);

          const minOverlap = Math.min(overlapLeft, overlapRight, overlapTop, overlapBottom);

          if (minOverlap === overlapLeft || minOverlap === overlapRight) {
            ball.dx *= -1;
          } else {
            ball.dy *= -1;
          }

          b.alive = false;
          score += 10 * (brickRows - r);
          spawnParticles(b.x + b.w / 2, b.y + b.h / 2, brickColors[r], 20);

          // Flash effect on canvas briefly
          ctx.fillStyle = 'rgba(255, 255, 255, 0.3)';
          ctx.fillRect(0, 0, W, H);
        }
      }
    }

    if (allBricksCleared && gameState === 'playing') {
      gameState = 'won';
      updateHUD();
      winFinalScore.textContent = 'FINAL SCORE: ' + score;
      setTimeout(() => {
        winScreen.classList.remove('hidden');
      }, 500);
      return;
    }

    // Ball out of bounds (bottom)
    if (ball.y + ball.r > H) {
      lives--;
      updateHUD();
      spawnParticles(ball.x, ball.y, '#e94560', 25);
      if (lives <= 0) {
        gameState = 'lost';
        gameOverFinalScore.textContent = 'FINAL SCORE: ' + score;
        setTimeout(() => {
          gameOverScreen.classList.remove('hidden');
        }, 500);
      } else {
        resetBall();
      }
    }

    updateParticles();
  }

  function draw() {
    // Background
    ctx.fillStyle = '#0f0f23';
    ctx.fillRect(0, 0, W, H);

    // Grid lines (subtle)
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.03)';
    ctx.lineWidth = 1;
    for (let x = 0; x < W; x += 40) {
      ctx.beginPath();
      ctx.moveTo(x, 0);
      ctx.lineTo(x, H);
      ctx.stroke();
    }
    for (let y = 0; y < H; y += 40) {
      ctx.beginPath();
      ctx.moveTo(0, y);
      ctx.lineTo(W, y);
      ctx.stroke();
    }

    // Bricks
    for (let r = 0; r < brickRows; r++) {
      for (let c = 0; c < brickCols; c++) {
        const b = bricks[r][c];
        if (!b.alive) continue;
        ctx.fillStyle = brickColors[r];
        // Rounded rectangle effect with shadow
        ctx.shadowColor = brickColors[r];
        ctx.shadowBlur = 8;
        roundRect(ctx, b.x, b.y, b.w, b.h, 4);
        ctx.fill();
        ctx.shadowBlur = 0;

        // Inner highlight
        ctx.fillStyle = 'rgba(255, 255, 255, 0.18)';
        roundRect(ctx, b.x + 3, b.y + 3, b.w - 6, (b.h / 2) - 3, 3);
        ctx.fill();

        // Inner shadow
        ctx.fillStyle = 'rgba(0, 0, 0, 0.25)';
        roundRect(ctx, b.x + 3, b.y + b.h / 2, b.w - 6, (b.h / 2) - 3, 3);
        ctx.fill();
      }
    }

    // Paddle with glow
    ctx.shadowColor = '#4fc3f7';
