        const osc2 = audioCtx.createOscillator();
        const gain2 = audioCtx.createGain();
        osc2.type = 'sine';
        osc2.frequency.setValueAtTime(600, now);
        osc2.frequency.exponentialRampToValueAtTime(400, now + 0.1);
        gain2.gain.setValueAtTime(0.08, now);
        gain2.gain.exponentialRampToValueAtTime(0.001, now + 0.1);
        osc2.connect(gain2);
        gain2.connect(audioCtx.destination);
        osc2.start(now);
        osc2.stop(now + 0.1);
        break;
      case 'wall': // Wall bounce
        const osc3 = audioCtx.createOscillator();
        const gain3 = audioCtx.createGain();
        osc3.type = 'triangle';
        osc3.frequency.setValueAtTime(400, now);
        osc3.frequency.exponentialRampToValueAtTime(250, now + 0.08);
        gain3.gain.setValueAtTime(0.06, now);
        gain3.gain.exponentialRampToValueAtTime(0.001, now + 0.08);
        osc3.connect(gain3);
        gain3.connect(audioCtx.destination);
        osc3.start(now);
        osc3.stop(now + 0.08);
        break;
      case 'life': // Life lost
        const osc4 = audioCtx.createOscillator();
        const gain4 = audioCtx.createGain();
        osc4.type = 'sawtooth';
        osc4.frequency.setValueAtTime(300, now);
        osc4.frequency.exponentialRampToValueAtTime(100, now + 0.3);
        gain4.gain.setValueAtTime(0.12, now);
        gain4.gain.exponentialRampToValueAtTime(0.001, now + 0.3);
        osc4.connect(gain4);
        gain4.connect(audioCtx.destination);
        osc4.start(now);
        osc4.stop(now + 0.3);
        break;
      case 'win': // Win celebration
        const osc5 = audioCtx.createOscillator();
        const gain5 = audioCtx.createGain();
        osc5.type = 'sine';
        osc5.frequency.setValueAtTime(523, now);
        osc5.frequency.setValueAtTime(659, now + 0.15);
        osc5.frequency.setValueAtTime(784, now + 0.3);
        osc5.frequency.setValueAtTime(1047, now + 0.45);
        gain5.gain.setValueAtTime(0.1, now);
        gain5.gain.exponentialRampToValueAtTime(0.001, now + 0.6);
        osc5.connect(gain5);
        gain5.connect(audioCtx.destination);
        osc5.start(now);
        osc5.stop(now + 0.6);
        break;
    }
  }

