      ball.dx = Math.cos(angle) * ball.speed;
      ball.dy = Math.sin(angle) * ball.speed;
      ball.y = paddle.y - ball.r - 1;

      spawnParticles(ball.x, ball.y, '#ffffff', 8);
    }

    let allBricksCleared = true;
    if (bricks && bricks.length > 0) {
      for (let r = 0; r < brickRows; r++) {
        if (!bricks[r]) continue;
        for (let c = 0; c < brickCols; c++) {
          const b = bricks[r][c];
          if (!b || !b.alive) continue;

          allBricksCleared = false;

          if (
            ball.x + ball.r > b.x &&
            ball.x - ball.r < b.x + b.w &&
            ball.y + ball.r > b.y &&
            ball.y - ball.r < b.y + b.h
          ) {
            const overlapLeft = (ball.x + ball.r) - b.x;
            const overlapRight = (b.x + b.w) - (ball.x - ball.r);
            const overlapTop = (ball.y + ball.r) - b.y;
            const overlapBottom = (b.y + b.h) - (ball.y - ball.r);

            const minOverlap = Math.min(overlapLeft, overlapRight, overlapTop, overlapBottom);

            if (minOverlap === overlapLeft || minOverlap === overlapRight) {
              ball.dx *= -1;
            } else {
              ball.dy *= -1;
            }

            b.alive = false;
            score += 10 * (brickRows - r);
            spawnParticles(b.x + b.w / 2, b.y + b.h / 2, brickColors[r], 20);
          }
        }
      }
    }

    if (allBricksCleared && gameState === 'playing') {
      gameState = 'won';
      updateHUD();
      winFinalScore.textContent = 'FINAL SCORE: ' + score;
      setTimeout(function() {
        winScreen.classList.remove('hidden');
      }, 500);
    }

    if (ball.y + ball.r > canvas.height) {
      lives--;
      updateHUD();
      spawnParticles(ball.x, ball.y, '#e94560', 25);
      playSFX('lose');
      if (lives <= 0) {
        gameState = 'lost';
        gameOverFinalScore.textContent = 'FINAL SCORE: ' + score;
        setTimeout(function() { gameOverScreen.classList.remove('hidden'); }, 500);
      } else {
        resetBall();
      }
    }

    updateParticles();
  }

  function draw() {
    ctx.fillStyle = '#0f0f23';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    drawParallax();

    if (gameState !== 'playing' && gameState !== 'won') return;

    initBackground();
    drawParallax();

    if (bricks && bricks.length > 0) {
      for (let r = 0; r < brickRows; r++) {
        if (!bricks[r]) continue;
        for (let c = 0; c < brickCols; c++) {
          const b = bricks[r][c];
          if (!b || !b.alive) continue;

          ctx.fillStyle = brickColors[r];
          roundRect(ctx, b.x, b.y, b.w, b.h, 4);
        }
      }
    }

    ctx.shadowColor = '#4fc3f7';
    ctx.shadowBlur = 15;
    const grad = ctx.createLinearGradient(paddle.x, paddle.y, paddle.x + paddle.w, paddle.y);
    grad.addColorStop(0, '#4fc3f7');
    grad.addColorStop(0.5, '#82b1ff');
    grad.addColorStop(1, '#4fc3f7');
    ctx.fillStyle = grad;
    roundRect(ctx, paddle.x, paddle.y, paddle.w, paddle.h, 8);
    ctx.fill();
    ctx.shadowBlur = 0;

    ctx.fillStyle = 'rgba(255, 255, 255, 0.3)';
    roundRect(ctx, paddle.x + 4, paddle.y + 2, paddle.w - 8, paddle.h / 2 - 2, 4);
    ctx.fill();

    ctx.shadowColor = '#e94560';
    ctx.shadowBlur = 12;
    ctx.fillStyle = '#ffffff';
    ctx.beginPath();
    ctx.arc(ball.x, ball.y, ball.r, 0, Math.PI * 2);
    ctx.fill();

    const ballGrad = ctx.createRadialGradient(
      ball.x - 3, ball.y - 3, 1,
      ball.x, ball.y, ball.r
    );
    ballGrad.addColorStop(0, 'rgba(255, 255, 255, 0.9)');
    ballGrad.addColorStop(1, '#e94560');
    ctx.fillStyle = ballGrad;
    ctx.beginPath();
    ctx.arc(ball.x, ball.y, ball.r, 0, Math.PI * 2);
    ctx.fill();
    ctx.shadowBlur = 0;

    drawParticles();
  }

  function roundRect(ctx, x, y, w, h, r) {
    if (w < 2 * r || h < 2 * r) return;
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.lineTo(x + w - r, y);
    ctx.quadraticCurveTo(x + w, y, x + w, y + r);
    ctx.lineTo(x + w, y + h - r);
    ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
    ctx.lineTo(x + r, y + h);
    ctx.quadraticCurveTo(x, y + h, x, y + h - r);
    ctx.lineTo(x, y + r);
    ctx.quadraticCurveTo(x, y, x + r, y);
    ctx.closePath();
  }

  function gameLoop() {
    update();
    draw();
    animationId = requestAnimationFrame(gameLoop);
  }

  playBtn.addEventListener('click', function() {
