// ===== HUD DRAWING =====
function drawHUD() {
    const W = canvas.width;
    const H = canvas.height;

    // Score bar at top
    ctx.fillStyle = 'rgba(0, 0, 0, 0.5)';
    ctx.fillRect(0, 0, W, 40);

    // HUD text
    ctx.fillStyle = '#e94560';
    ctx.font = '14px Courier New';
    ctx.textAlign = 'left';
    ctx.fillText('SCORE: ' + score.toString().padStart(6, ' '), 10, 28);

    // Lives with hearts
    let livesText = '';
    for (let i = 0; i < lives; i++) {
        livesText += '\u2764';
    }
    ctx.fillStyle = '#ff5252';
    ctx.textAlign = 'right';
    ctx.fillText(livesText, W - 10, 28);

    // Level indicator
    ctx.fillStyle = '#a8b2d1';
    ctx.font = '12px Courier New';
    ctx.textAlign = 'center';
    ctx.fillText('Level ' + (currentLevelIdx + 1) + '/' + LEVELS.length, W / 2, 24);

    // Coins counter
    ctx.fillStyle = '#ffd700';
    ctx.font = '12px Courier New';
    ctx.textAlign = 'left';
    ctx.fillText('COINS: ' + totalCoins.toString().padStart(3, ' '), 10, H - 8);
}

// ===== UPDATE HUD DOM ELEMENTS =====
function updateHUD() {
    if (!hudEl) return;

