    if (name === 'push') {
      // Try pushing crates in all directions
      for (var d = 0; d < 4; d++) {
        var dx, dy;
        if (d === 0) { dx = -1; dy = 0; }
        else if (d === 1) { dx = 1; dy = 0; }
        else if (d === 2) { dx = 0; dy = -1; }
        else { dx = 0; dy = 1; }

        var result = tryMove(dx, dy);
        if (result) return true;
      }
      return false;
    }

    if (name === 'advance') {
      // Advance to next level or win
      if (levelIndex < totalLevels - 1) {
