const audioCtx = new AudioContext();
let musicOsc1, musicOsc2, musicGain;
let sfxGain;
let muted = false;

function initAudio() {
    if (audioCtx.state === 'suspended') audioCtx.resume();
    musicGain = audioCtx.createGain();
    musicGain.gain.value = 0.15;
    musicGain.connect(audioCtx.destination);
    sfxGain = audioCtx.createGain();
    sfxGain.gain.value = 0.3;
    sfxGain.connect(audioCtx.destination);

    if (!musicOsc1) {
        musicOsc1 = audioCtx.createOscillator();
        musicOsc2 = audioCtx.createOscillator();
        musicOsc1.type = 'sine';
        musicOsc2.type = 'triangle';
        musicOsc1.frequency.value = 330;
        musicOsc2.frequency.value = 440;
        musicOsc1.connect(musicGain);
        musicOsc2.connect(musicGain);
    }

    if (!musicOsc1) return;
    const now = audioCtx.currentTime;
    musicOsc1.frequency.setValueAtTime(330, now);
    musicOsc2.frequency.setValueAtTime(440, now);
}

function playMusic() {
    initAudio();
    if (musicOsc1) {
        const now = audioCtx.currentTime;
        musicOsc1.start(now);
        musicOsc2.start(now);
    }
}

function stopMusic() {
    if (musicOsc1) {
        try { musicOsc1.stop(audioCtx.currentTime + 0.5); } catch(e){}
        try { musicOsc2.stop(audioCtx.currentTime + 0.5); } catch(e){}
    }
}

function playSFX(type) {
    if (muted || !sfxGain) return;
    const now = audioCtx.currentTime;
    const osc = audioCtx.createOscillator();
    const g = audioCtx.createGain();
    osc.connect(g);
    g.connect(sfxGain);

    switch(type) {
        case 'move':
            osc.type = 'sine';
            osc.frequency.setValueAtTime(600, now);
            osc.frequency.exponentialRampToValueAtTime(800, now + 0.1);
            g.gain.setValueAtTime(0.3, now);
            g.gain.exponentialRampToValueAtTime(0.01, now + 0.15);
            osc.start(now);
            osc.stop(now + 0.15);
            break;
        case 'push':
            osc.type = 'square';
            osc.frequency.setValueAtTime(200, now);
            osc.frequency.exponentialRampToValueAtTime(300, now + 0.15);
            g.gain.setValueAtTime(0.4, now);
            g.gain.exponentialRampToValueAtTime(0.01, now + 0.2);
            osc.start(now);
            osc.stop(now + 0.2);
            break;
        case 'win':
            osc.type = 'sine';
            osc.frequency.setValueAtTime(523, now);
            osc.frequency.setValueAtTime(659, now + 0.15);
            osc.frequency.setValueAtTime(784, now + 0.3);
            osc.frequency.setValueAtTime(1047, now + 0.45);
            g.gain.setValueAtTime(0.4, now);
            g.gain.exponentialRampToValueAtTime(0.01, now + 0.8);
            osc.start(now);
            osc.stop(now + 0.8);
            break;
        case 'lose':
            osc.type = 'sawtooth';
            osc.frequency.setValueAtTime(300, now);
            osc.frequency.exponentialRampToValueAtTime(150, now + 0.4);
            g.gain.setValueAtTime(0.4, now);
            g.gain.exponentialRampToValueAtTime(0.01, now + 0.6);
            osc.start(now);
            osc.stop(now + 0.6);
            break;
        case 'level':
            osc.type = 'sine';
            osc.frequency.setValueAtTime(440, now);
            osc.frequency.exponentialRampToValueAtTime(880, now + 0.2);
            g.gain.setValueAtTime(0.3, now);
            g.gain.exponentialRampToValueAtTime(0.01, now + 0.3);
            osc.start(now);
            osc.stop(now + 0.3);
            break;
    }
}

