// === PARALLAX LAYER DRAWER ===
function drawParallaxLayer(ctx, color, speed, offset) {
  ctx.fillStyle=color;
  const layerW = canvas.width * 2;
  const layerH = canvas.height + offset*3;
  ctx.fillRect(0,0,layerW,layerH);

  // Draw decorative elements
  for (let i=0; i<15; i++) {
    const x = ((i * 73) % layerW) - offset*2;
    const y = ((i * 47 + timeElapsed*speed) % (layerH-offset*3)) + offset;
    ctx.fillStyle='#2a1f15';
    ctx.fillRect(x, y, 8, 8);
  }
}

