  ctx.font='bold 10px Courier New';
  ctx.textAlign='center';
  const signs = { saloon:'SALOON', store:'STORE', sheriff:"SHERIFF", bank:'BANK' };
  ctx.fillText(signs[b.type]||b.type, b.x+b.w/2, b.y-14);
}

