function detectLocation() {
  const townCenterX = world.town.x + 300;
  const townCenterY = world.town.y + 200;

  const dx = player.x - townCenterX;
  const dy = player.y - townCenterY;
  const dist = Math.sqrt(dx * dx + dy * dy);

  if (dist < 350) {
    location = 'town';
  } else if (player.y < world.town.y || player.x > world.town.x + 600) {
    // Check for buildings
    for (let b of buildings) {
      const bdx = player.x - (b.x + b.w / 2);
      const bdy = player.y - (b.y + b.h / 2);
      if (Math.abs(bdx) < b.w / 2 && Math.abs(bdy) < b.h / 2) {
        location = b.type;
        return;
      }
    }
    location = 'desert';
  } else {
    location = 'desert';
  }
}

