function gameLoop(timestamp) { if (gameState !== "playing") { requestAnimationFrame(gameLoop); return; } 
  if (gameState !== 'playing') return;

  updateTime();
  updateHunger();
  updateMining();

  // Update particles
  for (let i = particles.length - 1; i >= 0; i--) {
    const p = particles[i];
    p.x += p.vx;
    p.y += p.vy;
    p.life -= 0.02;

    if (p.life <= 0) {
      particles.splice(i, 1);
    }
  }

  // Clear canvas
  ctx.fillStyle = '#0d0d1a';
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  // Draw background based on location
  switch(location) {
    case 'town':
      drawTown();
      break;
    case 'desert':
      drawDesert();
      break;
    case 'cave':
      drawCave();
      break;
    case 'river':
      drawRiver();
      break;
  }

  // Draw player
  drawPlayer();

  // Draw particles
  particles.forEach(p => {
    ctx.globalAlpha = p.life;
    ctx.fillStyle = p.color;
    ctx.fillRect(p.x, p.y, 3, 3);
  });
  ctx.globalAlpha = 1.0;

  drawHUD();
  drawMinimap();

  requestAnimationFrame(gameLoop);
}

