      audioCtx = new (window.AudioContext || window.webkitAudioContext)();

      // Start ambient music loop
      startAmbientMusic();

      // Create SFX sounds
      createSound('pickup', () => playPickupSound());
      createSound('action', () => playActionSound());
      createSound('danger', () => playDangerSound());
    } catch(e) {
      console.log('Audio not available');
    }
  } else if (audioCtx.state === 'suspended') {
    audioCtx.resume();
  }
}

function startAmbientMusic() {
  // Simple ambient drone using oscillators
  const notes = [261.63, 329.63, 392.00, 523.25]; // C major pentatonic

  for (let i=0; i<4; i++) {
    let osc = audioCtx.createOscillator();
    let gain = audioCtx.createGain();

    osc.type = 'sine';
    osc.frequency.value = notes[i] * 0.7; // Lower octave

    gain.gain.value = 0.05 + Math.random() * 0.03;

    osc.connect(gain);
    gain.connect(audioCtx.destination);

    osc.start();
    musicOscillators.push({ osc, gain });
  }
}

function playPickupSound() {
  if (!audioCtx) return;

  let osc = audioCtx.createOscillator();
  let gain = audioCtx.createGain();

  osc.type = 'sine';
  osc.frequency.setValueAtTime(800, audioCtx.currentTime);
  osc.frequency.exponentialRampToValueAtTime(1200, audioCtx.currentTime + 0.1);

  gain.gain.setValueAtTime(0.3, audioCtx.currentTime);
  gain.gain.exponentialRampToValueAtTime(0.01, audioCtx.currentTime + 0.15);

  osc.connect(gain);
  gain.connect(audioCtx.destination);
  osc.start();
  osc.stop(audioCtx.currentTime + 0.2);
}

function playActionSound() {
  if (!audioCtx) return;

  let osc = audioCtx.createOscillator();
  let gain = audioCtx.createGain();

  osc.type = 'square';
  osc.frequency.setValueAtTime(150, audioCtx.currentTime);
  osc.frequency.exponentialRampToValueAtTime(60, audioCtx.currentTime + 0.2);

  gain.gain.setValueAtTime(0.2, audioCtx.currentTime);
  gain.gain.exponentialRampToValueAtTime(0.01, audioCtx.currentTime + 0.25);

  osc.connect(gain);
  gain.connect(audioCtx.destination);
  osc.start();
  osc.stop(audioCtx.currentTime + 0.3);
}

function playDangerSound() {
  if (!audioCtx) return;

  let osc = audioCtx.createOscillator();
  let gain = audioCtx.createGain();

  osc.type = 'sawtooth';
  osc.frequency.setValueAtTime(200, audioCtx.currentTime);
  osc.frequency.exponentialRampToValueAtTime(50, audioCtx.currentTime + 0.4);

  gain.gain.setValueAtTime(0.3, audioCtx.currentTime);
  gain.gain.exponentialRampToValueAtTime(0.01, audioCtx.currentTime + 0.5);

  osc.connect(gain);
  gain.connect(audioCtx.destination);
  osc.start();
  osc.stop(audioCtx.currentTime + 0.6);
}

