// === HUNTING MINIGAME ===
let huntTargetX = 300;
let huntTargetY = 250;
let huntTimer = 0;
function updateHunting(dt) {
  huntTimer += dt;

  // Move target
  huntTargetX += Math.sin(huntTimer * 1.8) * 4;
  huntTargetY += Math.cos(huntTimer * 2) * 3;

  // Check if player is close enough to strike
  const dist = Math.sqrt(Math.pow(playerX - huntTargetX, 2) + Math.pow(playerY - huntTargetY, 2));

  if (dist < 80 && keys['Space']) {
    gold += Math.floor(Math.random() * 15) + 10;
    energy -= 5;
    showDialog('You hunted your prey! Reward: $' + (Math.floor(Math.random() * 15) + 10));
    endMinigame(true);
  }

  // Target runs away if too close
  if (dist < 120) {
    huntTargetX += (huntTargetX - playerX) * 0.03;
    huntTargetY += (huntTargetY - playerY) * 0.03;
  }

  // Check for exhaustion
  if (energy <= 0) {
    endMinigame(false);
  }
}

