function drawSnake() {
  // Draw body segments with gradient effect
  for (let i = snake.length - 1; i >= 0; i--) {
    const seg = snake[i];
    const ratio = i / snake.length;

    if (i === 0) {
      // Head - brighter, distinct color
      ctx.fillStyle = '#4ecca3';
      ctx.shadowColor = '#4ecca3';
      ctx.shadowBlur = 8;
    } else if (ratio > 0.7) {
      // Front body - bright green
      ctx.fillStyle = `rgb(${126 + Math.floor(ratio*5)}, ${204 + Math.floor(ratio*30)}, ${163 + Math.floor(ratio*20)})`;
    } else if (ratio > 0.4) {
      // Middle body - medium green
      ctx.fillStyle = `rgb(${80 + Math.floor(ratio*50)}, ${170 + Math.floor(ratio*40)}, ${130 + Math.floor(ratio*30)})`;
    } else {
      // Tail - darker green
      ctx.fillStyle = `rgb(${60 + Math.floor(ratio*80)}, ${140 + Math.floor(ratio*70)}, ${90 + Math.floor(ratio*50)})`;
    }

    const sx = seg.x * cellSize;
    const sy = seg.y * cellSize;
    const sw = cellSize - 1;
    const sh = cellSize - 1;

    // Rounded rectangle effect
    ctx.beginPath();
    ctx.moveTo(sx + 2, sy);
    ctx.lineTo(sx + sw - 2, sy);
    ctx.quadraticCurveTo(sx + sw, sy, sx + sw, sy + 2);
    ctx.lineTo(sx + sw, sy + sh - 2);
    ctx.quadraticCurveTo(sx + sw, sy + sh, sx + sw - 2, sy + sh);
    ctx.lineTo(sx + 2, sy + sh);
    ctx.quadraticCurveTo(sx, sy + sh, sx, sy + sh - 2);
    ctx.lineTo(sx, sy + 2);
    ctx.quadraticCurveTo(sx, sy, sx + 2, sy);
    ctx.closePath();
    ctx.fill();

    // Eyes on head
    if (i === 0) {
      ctx.shadowBlur = 0;
      const eyeOffsetX = dirX * 4;
      const eyeOffsetY = dirY * 4;

      ctx.fillStyle = '#fff';
      ctx.beginPath();
      ctx.arc(sx + cellSize/2 - 3 + eyeOffsetX, sy + cellSize/2 - 3 + eyeOffsetY, 3, 0, Math.PI*2);
      ctx.fill();

      ctx.beginPath();
      ctx.arc(sx + cellSize/2 + 3 + eyeOffsetX, sy + cellSize/2 - 3 + eyeOffsetY, 3, 0, Math.PI*2);
      ctx.fill();

      ctx.fillStyle = '#1a1a2e';
      ctx.beginPath();
      ctx.arc(sx + cellSize/2 - 3 + eyeOffsetX + dirX, sy + cellSize/2 - 3 + eyeOffsetY + dirY, 1.5, 0, Math.PI*2);
      ctx.fill();

      ctx.beginPath();
      ctx.arc(sx + cellSize/2 + 3 + eyeOffsetX + dirX, sy + cellSize/2 - 3 + eyeOffsetY + dirY, 1.5, 0, Math.PI*2);
      ctx.fill();
    }

    ctx.shadowBlur = 0;
  }
}

function drawFood() {
  if (!food) return;

  const fx = food.x * cellSize + cellSize/2;
  const fy = food.y * cellSize + cellSize/2;

  // Pulsing animation
  const pulse = 1 + Math.sin(Date.now() / 200) * 0.15;

  ctx.fillStyle = '#ff4757';
  ctx.shadowColor = '#ff4757';
  ctx.shadowBlur = 12;

  // Draw apple shape (circle with stem)
  ctx.beginPath();
  ctx.arc(fx, fy, cellSize/3 * pulse, 0, Math.PI*2);
  ctx.fill();

  ctx.fillStyle = '#2ed573';
  ctx.fillRect(fx - 1, fy - cellSize/4 - 2, 2, cellSize/4 + 2);

  ctx.shadowBlur = 0;
}

