// Input handling - addEventListener ONLY, no inline handlers
document.addEventListener('keydown', e => {
  const code = e.code;

  // Prevent default for arrow keys and WASD to avoid page scrolling
  if (['ArrowUp','ArrowDown','ArrowLeft','ArrowRight','Space'].includes(code)) {
    e.preventDefault();
  }

  switch(code) {
    case 'ArrowUp':
    case 'KeyW':
      if (!isOppositeDir(0, -1)) { nextDirX = 0; nextDirY = -1; }
      break;
    case 'ArrowDown':
    case 'KeyS':
      if (!isOppositeDir(0, 1)) { nextDirX = 0; nextDirY = 1; }
      break;
    case 'ArrowLeft':
    case 'KeyA':
      if (!isOppositeDir(-1, 0)) { nextDirX = -1; nextDirY = 0; }
      break;
    case 'ArrowRight':
    case 'KeyD':
      if (!isOppositeDir(1, 0)) { nextDirX = 1; nextDirY = 0; }
      break;
  }
});

// Touch/swipe support
let touchStartX = 0, touchStartY = 0;
canvas.addEventListener('touchstart', e => {
  const t = e.touches[0];
  touchStartX = t.clientX;
  touchStartY = t.clientY;
}, false);

canvas.addEventListener('touchend', e => {
  const t = e.changedTouches[0];
  const dx = t.clientX - touchStartX;
  const dy = t.clientY - touchStartY;

  if (Math.abs(dx) > Math.abs(dy)) {
    // Horizontal swipe
    if (!isOppositeDir(dx > 0 ? 1 : -1, 0)) { nextDirX = dx > 0 ? 1 : -1; nextDirY = 0; }
  } else {
    // Vertical swipe
    if (!isOppositeDir(0, dy > 0 ? 1 : -1)) { nextDirX = 0; nextDirY = dy > 0 ? 1 : -1; }
  }
}, false);

// Game tick loop (separate from RAF for speed control)
let lastTickTime = 0;
function gameLoop(timestamp) { if (gameState !== "playing") { requestAnimationFrame(gameLoop); return; } 
  if (!lastTickTime) lastTickTime = timestamp;

  const elapsed = timestamp - lastTickTime;

  // Update particles every frame
  updateParticles();

  // Game tick based on current speed
  if (elapsed >= currentTickMs && gameState === 'playing') {
    lastTickTime = timestamp;

    const result = moveSnake();

    if (result === 'wall' || result === 'self') {
      deaths++;
      playSFX('die');

      // Death particles
      for (let i = 0; i < snake.length; i++) {
        spawnParticles(snake[i].x * cellSize, snake[i].y * cellSize, '#4ecca3', 2);
      }

      gameState = 'lost';
    } else if (result === undefined) {
      // Normal move - no food eaten
    }

    updateHUD();
  }

  drawBg();
  drawFood();
  drawSnake();
  drawParticles();

  requestAnimationFrame(gameLoop);
}

// Start game handler
function startGame() {
  initAudio();
  if (audioCtx.state === 'suspended') audioCtx.resume();

  // Reset all state
  snake = [];
  dirX = 1; dirY = 0; nextDirX = 1; nextDirY = 0;
  score = 0; foodsEaten = 0; deaths = 0;
  currentTickMs = baseSpeed;

  // Initial snake segments
  for (let i = 0; i < 3; i++) {
    snake.push({ x: 15 - i, y: 15 });
  }

  generateFood();
  initBg();
  updateCamera();
  updateHUD();

  // Hide overlay immediately
  overlay.classList.add('hidden');
  gameState = 'playing';
  canvas.focus();

  // Start audio
  startMusic();

  // Kick off game loop
  lastTickTime = performance.now();
  requestAnimationFrame(gameLoop);
}

// Wire Play button with addEventListener (unique ID)
playBtn.addEventListener('click', () => {
  initAudio();
  if (audioCtx.state === 'suspended') audioCtx.resume();

  overlay.classList.add('hidden');
  gameState = 'playing';
  canvas.focus();

  // Start music and loop
  startMusic();
  lastTickTime = performance.now();
  requestAnimationFrame(gameLoop);
});

// Wire mute button with addEventListener (unique ID)
muteBtn.addEventListener('click', () => {
  toggleMute();
});

// Initial draw to show something before play
function initialDraw() {
  ctx.fillStyle = '#0f0f23';
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  // Draw grid
  ctx.strokeStyle = 'rgba(255,255,255,0.05)';
