    // Draw food as a circle with glow
    ctx.beginPath();
    ctx.arc(food.x * cellSize + cellSize/2, food.y * cellSize + cellSize/2, (cellSize/2 - 4) + pulse, 0, Math.PI * 2);
    ctx.fill();

    // Inner highlight
    ctx.fillStyle = '#fff';
    ctx.beginPath();
    ctx.arc(food.x * cellSize + cellSize/2 - 2, food.y * cellSize + cellSize/2 - 2, 3, 0, Math.PI * 2);
    ctx.fill();

    ctx.shadowBlur = 0;
  }

  // Draw snake body with gradient colors
  for (let i = snake.length - 1; i >= 0; i--) {
    const s = snake[i];
    const ratio = i / snake.length;
    const r = Math.floor(76 + (233 - 76) * ratio);
    const g = Math.floor(78 + (202 - 78) * ratio);
    const b = Math.floor(160 + (96 - 160) * ratio);

    ctx.fillStyle = `rgb(${r},${g},${b})`;

    // Draw rounded rectangle for each segment
    const pad = i === 0 ? 2 : 3;
    roundRect(ctx, s.x * cellSize + pad, s.y * cellSize + pad, cellSize - pad*2, cellSize - pad*2, 4);

    // Draw eyes on head
    if (i === 0) {
      ctx.fillStyle = '#fff';
      const eyeOffsetX = direction.x * 5;
      const eyeOffsetY = direction.y * 5;

      ctx.beginPath();
      ctx.arc(s.x * cellSize + cellSize/2 - 6 + eyeOffsetX, s.y * cellSize + cellSize/2 - 6 + eyeOffsetY, 3, 0, Math.PI*2);
      ctx.fill();

      ctx.beginPath();
      ctx.arc(s.x * cellSize + cellSize/2 + 6 + eyeOffsetX, s.y * cellSize + cellSize/2 - 6 + eyeOffsetY, 3, 0, Math.PI*2);
      ctx.fill();
    }
  }

  // Draw particles
  for (const p of particles) {
    ctx.fillStyle = p.color;
    ctx.globalAlpha = p.life;
    ctx.beginPath();
    ctx.arc(p.x, p.y, p.size * p.life, 0, Math.PI*2);
    ctx.fill();
  }
  ctx.globalAlpha = 1;

  ctx.restore();
}

function roundRect(ctx, x, y, w, h, r) {
  ctx.beginPath();
  ctx.moveTo(x + r, y);
  ctx.lineTo(x + w - r, y);
  ctx.quadraticCurveTo(x + w, y, x + w, y + r);
  ctx.lineTo(x + w, y + h - r);
  ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
  ctx.lineTo(x + r, y + h);
  ctx.quadraticCurveTo(x, y + h, x, y + h - r);
  ctx.lineTo(x, y + r);
  ctx.quadraticCurveTo(x, y, x + r, y);
  ctx.closePath();
  ctx.fill();
}

